import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TimePhase {
  MORNING = 'MORNING',
  DAY = 'DAY',
  EVENING = 'EVENING',
  LATE_NIGHT = 'LATE_NIGHT'
}

export interface WeatherData {
  current: string;
  temp: number;
  condition: string;
  forecast: { time: string; temp: number; icon: string }[];
}

export interface NewsArticle {
  title: string;
  source: string;
  category: string;
}

export interface BriefContent {
  greeting: string;
  subtext: string;
  weather: WeatherData;
  focusScore: number;
  news: NewsArticle[];
  breakdown: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase): Promise<BriefContent> {
  const prompt = `
    Generate a Samsung-style AI daily briefing for the following time of day: ${phase}.
    Return exactly the JSON requested.

    Weather context: It is currently a slightly ${phase === TimePhase.MORNING ? 'cloudy morning' : phase === TimePhase.LATE_NIGHT ? 'clear and cold night' : 'sunny and warm day'}.

    The response must follow this schema:
    {
      "greeting": "string (e.g. Good Morning, The day rolls on, etc)",
      "subtext": "string based on requirements",
      "weather": {
        "current": "string (e.g. Heavy rainfall)",
        "temp": number,
        "condition": "string",
        "forecast": [
          {"time": "string (HH:00)", "temp": number, "icon": "string (sun, cloud, rain, moon)"}
        ] (6 hours)
      },
      "focusScore": number (0-100),
      "news": [
        {"title": "string", "source": "string", "category": "string"}
      ] (3 articles),
      "breakdown": ["string"] (3 items describing the next few hours)
    }

    Specific Rules for Subtext:
    - MORNING: "Your day starts with [weather.current]. Have a cheerful day."
    - DAY: "Enjoy the rest of the day"
    - EVENING: "Enjoy the rest of your day"
    - LATE_NIGHT: "Have a Good and Restful Night"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");
    return content;
  } catch (error) {
    console.error("Error fetching Gemini content:", error);
    // Fallback static data if API fails
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  return {
    greeting: phase === TimePhase.MORNING ? "Good Morning" : phase === TimePhase.DAY ? "The day rolls on" : phase === TimePhase.EVENING ? "Good Evening" : "Late night recap",
    subtext: "System initializing...",
    weather: {
      current: "Partly Cloudy",
      temp: 24,
      condition: "Cloudy",
      forecast: Array.from({ length: 6 }).map((_, i) => ({
        time: `${(new Date().getHours() + i + 1) % 24}:00`,
        temp: 22 + i,
        icon: "cloud"
      }))
    },
    focusScore: 85,
    news: [
      { title: "New Galaxy features announced", source: "Samsung News", category: "Tech" },
      { title: "Global market trends update", source: "Reuters", category: "Finance" },
      { title: "Local park renovation complete", source: "City Times", category: "Local" }
    ],
    breakdown: ["Review morning reports", "Team syncing at 11:00", "Lunch break at 13:00"]
  };
}

import React from 'react';

interface ShimmerTextProps {
  children: React.ReactNode;
  className?: string;
  isLarge?: boolean;
}

export const ShimmerText: React.FC<ShimmerTextProps> = ({ children, className = "", isLarge = false }) => {
  return (
    <div className={`shimmer-effect ${isLarge ? 'font-bold' : ''} ${className}`}>
      {children}
    </div>
  );
};

import React from 'react';
import { Cloud, Sun, CloudRain, Moon, Thermometer } from 'lucide-react';
import { WeatherData } from '../types';
import { ShimmerText } from './ShimmerText';

const WeatherIcon = ({ condition, className = "" }: { condition: string; className?: string }) => {
  const cond = condition.toLowerCase();
  if (cond.includes('sun') || cond.includes('clear')) return <Sun className={className} />;
  if (cond.includes('rain')) return <CloudRain className={className} />;
  if (cond.includes('moon') || cond.includes('night')) return <Moon className={className} />;
  return <Cloud className={className} />;
};

export const WeatherCard: React.FC<{ data: WeatherData }> = ({ data }) => {
  return (
    <div className="glass-card rounded-[40px] p-6 w-full mb-4">
      <div className="flex justify-between items-start mb-6">
        <div>
          <ShimmerText className="text-sm font-medium opacity-80 mb-1">Here's the weather Today</ShimmerText>
          <div className="flex items-center gap-2">
            <span className="text-4xl font-bold text-white">{data.temp}°</span>
            <WeatherIcon condition={data.condition} className="w-8 h-8 text-blue-300" />
          </div>
          <ShimmerText className="text-lg font-medium">{data.current}</ShimmerText>
        </div>
      </div>

      <div className="flex justify-between items-center gap-4 overflow-x-auto pb-2">
        {data.forecast.map((item, idx) => (
          <div key={idx} className="flex flex-col items-center min-w-[50px]">
            <span className="text-xs text-white/60 mb-2">{item.time}</span>
            <WeatherIcon condition={item.icon} className="w-6 h-6 text-white/80 mb-2" />
            <span className="text-sm font-semibold text-white">{item.temp}°</span>
          </div>
        ))}
      </div>
    </div>
  );
};

