import React, { useState, useEffect, useCallback } from 'react';
import { TimePhase, BriefContent } from './types';
import { getBriefingContent } from './geminiService';
import { ShimmerText } from './components/ShimmerText';
import { WeatherCard } from './components/WeatherCard';
import { FocusScoreCard } from './components/FocusScoreCard';
import { NewsCard } from './components/NewsCard';
import { Sparkles, Calendar } from 'lucide-react';

const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [phase, setPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [isLoading, setIsLoading] = useState(true);

  const updatePhase = useCallback(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return TimePhase.MORNING;
    if (hour >= 12 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT;
  }, []);

  const initialize = useCallback(async () => {
    setIsLoading(true);
    const currentPhase = updatePhase();
    setPhase(currentPhase);
    const data = await getBriefingContent(currentPhase);
    setContent(data);
    setIsLoading(false);
  }, [updatePhase]);

  useEffect(() => {
    initialize();
    // Refresh every hour
    const interval = setInterval(initialize, 3600000);
    return () => clearInterval(interval);
  }, [initialize]);

  if (!content && isLoading) {
    return (
      <div className="h-screen w-screen flex items-center justify-center bg-black">
        <div className="flex flex-col items-center gap-4">
          <Sparkles className="w-12 h-12 text-blue-400 animate-pulse" />
          <ShimmerText className="text-xl font-medium">Galaxy AI is briefing...</ShimmerText>
        </div>
      </div>
    );
  }

  return (
    <div className="relative h-screen w-screen bg-black overflow-hidden flex flex-col items-center">
      {/* Background Video - Simulated Placeholder for Samsung Style */}
      <video
        autoPlay
        loop
        muted
        playsInline
        className="absolute top-0 left-0 w-full h-full object-cover opacity-60 pointer-events-none"
      >
        <source src="https://assets.mixkit.co/videos/preview/mixkit-abstract-motion-of-colors-blue-and-purple-34531-large.mp4" type="video/mp4" />
      </video>

      {/* Galaxy AI Logo (Top Left) */}
      <div className="absolute top-12 left-8 z-20 flex items-center gap-2 ai-logo-container">
        <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center">
          <Sparkles className="w-5 h-5 text-white" />
        </div>
        <span className="text-white/90 text-sm font-semibold tracking-tight">Galaxy AI</span>
      </div>

      {/* Main Content Area */}
      <div className="relative z-10 w-full max-w-md h-full flex flex-col pt-24 pb-12 px-8 overflow-y-auto">

        {/* Header Section */}
        <header className="mb-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
          <ShimmerText isLarge className="text-5xl tracking-tight mb-2">
            {content?.greeting}
          </ShimmerText>
          <ShimmerText className="text-xl opacity-90 leading-relaxed font-light">
            {content?.subtext}
          </ShimmerText>
        </header>

        {/* Cards Section */}
        <main className="flex flex-col gap-4 animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-200">
          {content && (
            <>
              <WeatherCard data={content.weather} />

              <FocusScoreCard score={content.focusScore} />

              <NewsCard news={content.news} />

              {/* Day Breakdown (Show from 'Day rolls on' onwards) */}
              {(phase !== TimePhase.MORNING) && content.breakdown.length > 0 && (
                <div className="glass-card rounded-[40px] p-6 w-full mb-4">
                  <ShimmerText className="text-sm font-medium opacity-80 mb-4 flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Here's is the break down of your day
                  </ShimmerText>
                  <div className="space-y-4">
                    {content.breakdown.map((item, i) => (
                      <div key={i} className="flex gap-4 items-center">
                        <div className="w-2 h-2 rounded-full bg-blue-400" />
                        <ShimmerText className="text-sm font-medium">{item}</ShimmerText>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </>
          )}
        </main>

        <footer className="mt-auto pt-8 text-center">
            <div className="text-[10px] text-white/30 tracking-[0.2em] uppercase">Powered by Gemini & Galaxy AI</div>
        </footer>
      </div>

      {/* Overlay Vignette */}
      <div className="absolute inset-0 pointer-events-none bg-gradient-to-t from-black via-transparent to-black/30" />
    </div>
  );
};

export default App;

