import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase): Promise<BriefContent> {
  const prompt = `
    Generate a Samsung-style AI daily briefing for the following time of day: ${phase}.
    Return exactly the JSON requested.

    Weather context: It is currently a slightly ${phase === TimePhase.MORNING ? 'cloudy morning' : phase === TimePhase.LATE_NIGHT ? 'clear and cold night' : 'sunny and warm day'}.

    The response must follow this schema:
    {
      "greeting": "string (e.g. Good Morning, The day rolls on, Late night recap)",
      "subtext": "string based on requirements",
      "weather": {
        "current": "string (e.g. Heavy rainfall)",
        "temp": number,
        "condition": "string",
        "forecast": [
          {"time": "string (HH:00)", "temp": number, "icon": "string (sun, cloud, rain, moon)"}
        ] (6 hours)
      },
      "focusScore": number (0-100),
      "news": [
        {"title": "string", "source": "string", "category": "string"}
      ] (3 articles),
      "breakdown": ["string"] (3 items describing the next few hours)
    }

    Specific Rules for Subtext (CRITICAL):
    - MORNING: "Your day starts with [weather.current]. Have a cheerful day."
    - DAY: "Enjoy the rest of the day"
    - EVENING: "Enjoy the rest of your day"
    - LATE_NIGHT: "Have a Good Night"
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");
    return content;
  } catch (error) {
    console.error("Error fetching Gemini content:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  return {
    greeting: phase === TimePhase.MORNING ? "Good Morning" : phase === TimePhase.DAY ? "The day rolls on" : phase === TimePhase.EVENING ? "Good Evening" : "Late night recap",
    subtext: phase === TimePhase.LATE_NIGHT ? "Have a Good Night" : "System initializing...",
    weather: {
      current: "Partly Cloudy",
      temp: 24,
      condition: "Cloudy",
      forecast: Array.from({ length: 6 }).map((_, i) => ({
        time: `${(new Date().getHours() + i + 1) % 24}:00`,
        temp: 22 + i,
        icon: "cloud"
      }))
    },
    focusScore: 85,
    news: [
      { title: "New Galaxy features announced", source: "Samsung News", category: "Tech" },
      { title: "Global market trends update", source: "Reuters", category: "Finance" },
      { title: "Local park renovation complete", source: "City Times", category: "Local" }
    ],
    breakdown: ["Review morning reports", "Team syncing at 11:00", "Lunch break at 13:00"]
  };
}

