            <div className="h-20 w-72 bg-black/5 rounded-3xl animate-pulse" />
          )}
        </header>

        {/* SECONDARY CONTENT - Delayed Entrance */}
        {content && (
          <div className="delayed-content flex flex-col gap-14">
            {/* SUBTEXT (e.g., "Have a Good Night") */}
            <div className="-mt-12 mb-2">
              <ShimmerText className="text-[28px] font-medium leading-snug tracking-tight text-black/90">
                {content.subtext}
              </ShimmerText>
            </div>

            {/* CONTENT MODULES */}
            <div className="flex flex-col gap-10">
              {/* Weather Module */}
              <section>
                <ShimmerText className="text-[10px] font-bold uppercase tracking-[0.4em] ml-4 mb-4 text-black/30">
                  Daily Briefing
                </ShimmerText>
                <WeatherCard data={content.weather} />
              </section>

              {/* Focus Intelligence */}
              <section>
                <ShimmerText className="text-[10px] font-bold uppercase tracking-[0.4em] ml-4 mb-4 text-black/30">
                  Galaxy Analytics
                </ShimmerText>
                <FocusScoreCard score={content.focusScore} />
              </section>

              {/* News Briefing */}
              <section>
                <ShimmerText className="text-[10px] font-bold uppercase tracking-[0.4em] ml-4 mb-4 text-black/30">
                  Insights for You
                </ShimmerText>
                <NewsCard news={content.news} />
              </section>

              {/* Personalized Agenda */}
              {content.breakdown.length > 0 && (
                <section>
                   <ShimmerText className="text-[10px] font-bold uppercase tracking-[0.4em] ml-4 mb-4 text-black/30 flex items-center gap-2">
                    <Calendar className="w-3 h-3" />
                    Timeline
                  </ShimmerText>
                  <div className="glass-card card-shimmer rounded-[40px] p-10 w-full">
                    <div className="space-y-8">
                      {content.breakdown.map((item, i) => (
                        <div key={i} className="flex gap-6 items-center">
                          <div className="w-1.5 h-1.5 rounded-full bg-black/80 shrink-0" />
                          <span className="text-[16px] font-bold text-black/90 leading-tight tracking-tight">{item}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </section>
              )}
