  useEffect(() => {
    initialize();
    // Re-check phase every minute to ensure timely transitions
    const interval = setInterval(initialize, 60000);
    return () => clearInterval(interval);
  }, [initialize]);

  // Only show breakdown header and section from DAY phase onwards
  const showBreakdown = currentPhase !== TimePhase.MORNING;

  return (
    <div className="relative h-screen w-screen overflow-hidden flex flex-col items-center">
      {/* Arctic Background Container */}
      <div className="absolute inset-0 bg-gradient-to-br from-[#e0f7fa] via-[#e1f5fe] to-[#b3e5fc]" />

