              {/* Weather Module */}
              <section>
                <ShimmerText className="text-[12px] font-bold uppercase tracking-[0.1em] ml-1 mb-3 text-[#0f172a]/40">
                  Here's the weather Today
                </ShimmerText>
                <WeatherCard data={content.weather} />
              </section>

              {/* Focus Intelligence */}
              <section>
                <ShimmerText className="text-[12px] font-bold uppercase tracking-[0.1em] ml-1 mb-3 text-[#0f172a]/40">
                  Here's your todays focus score
                </ShimmerText>
                <FocusScoreCard score={content.focusScore} />
              </section>

              {/* News Briefing */}
              <section>
                <ShimmerText className="text-[12px] font-bold uppercase tracking-[0.1em] ml-1 mb-3 text-[#0f172a]/40">
                  Here's todays current affairs
