                    Heres is the break down of your day
                  </ShimmerText>
                  <div className="glass-card card-shimmer rounded-[35px] p-8 w-full border-t border-white/60">
                    <div className="space-y-6">
                      {content.breakdown.map((item, i) => (
                        <div key={i} className="flex gap-4 items-center">
                          <div className="w-1.5 h-1.5 rounded-full bg-[#0f172a]/60 shrink-0" />
