import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase): Promise<BriefContent> {
  const prompt = `
    Generate a Samsung-style AI daily briefing for: ${phase}.
    Do NOT include any user names.

    Return JSON:
    {
      "greeting": "string (strictly match: Good Morning, The day rolls on, Good evening, or Late night recap)",
      "weather": {
        "current": "string (natural description like 'Heavy rainfall', 'Cloudy morning', 'Thunderstorms')",
        "temp": number,
        "condition": "string",
        "forecast": [
          {"time": "string", "temp": number, "icon": "string"}
        ]
      },
      "focusScore": number,
      "news": [
        {"title": "string", "source": "string", "category": "string"}
      ] (exactly 5 articles),
      "breakdown": ["string"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    // STRICT PHRASE ENFORCEMENT
    if (phase === TimePhase.MORNING) {
      content.greeting = "Good Morning";
      content.subtext = `Your day starts with ${content.weather.current}. Have a cheerful day.`;
    } else if (phase === TimePhase.DAY) {
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
    } else if (phase === TimePhase.EVENING) {
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
    } else if (phase === TimePhase.LATE_NIGHT) {
      content.greeting = "Late night recap";
      content.subtext = "Have a Good and Restful Night";
    }

    // Ensure we only have 5 news items if model over-generates
    if (content.news && content.news.length > 5) {
      content.news = content.news.slice(0, 5);
    }

    return content;
  } catch (error) {
    console.error("Error fetching Gemini content:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  const weatherDesc = "cloudy morning";
  let greeting = "";
  let subtext = "";

  if (phase === TimePhase.MORNING) {
    greeting = "Good Morning";
    subtext = `Your day starts with ${weatherDesc}. Have a cheerful day.`;
  } else if (phase === TimePhase.DAY) {
    greeting = "The day rolls on";
    subtext = "Enjoy the rest of the day";
  } else if (phase === TimePhase.EVENING) {
    greeting = "Good evening";
    subtext = "Enjoy the rest of your day";
  } else {
    greeting = "Late night recap";
    subtext = "Have a Good and Restful Night";
  }

  return {
    greeting,
    subtext,
    weather: {
      current: weatherDesc,
      temp: 21,
      condition: "Cloudy",
      forecast: []
    },
    focusScore: 88,
    news: [
      { title: "Galaxy AI ecosystem expands with new features", source: "TechDaily", category: "Technology" },
      { title: "Global market trends show positive growth", source: "Finance World", category: "Business" },
      { title: "Innovative sustainable energy solutions unveiled", source: "Green Tech", category: "Science" },
      { title: "Cultural festival attracts thousands downtown", source: "City News", category: "Local" },
      { title: "Breakthrough in AI-driven healthcare research", source: "Medical Journal", category: "Health" }
    ],
    breakdown: ["Relax and unwind", "Prepare for sleep", "Sleep monitoring active"]
  };
}

