const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase): Promise<BriefContent> {
  const prompt = `
    Generate a Samsung-style AI daily briefing for: ${phase}.
    Return JSON:
    {
      "greeting": "string (Morning brief, Midday brief, Evening brief, or Late night brief)",
      "subtext": "string (Start your day with this briefing, Enjoy the rest of your day, etc.)",
      "summaryText": "string (A paragraph summary of weather and day like: 'Cloudy. Highs 17 to 19C and lows 7 to 9C. Good weather for running.')",
      "weather": {
        "current": "string (e.g. Sunny, Cloudy)",
        "temp": number,
        "high": number,
        "low": number,
        "location": "string (e.g. San Francisco)",
        "condition": "string",
        "sunset": "string (e.g. 5:29 PM)",
        "comparison": "string (e.g. Temperature a little lower than yesterday)",
        "forecast": []
      },
      "energyScore": number,
      "energyStatus": "string (e.g. Well rested, Ready to go)",
      "news": [
        {"title": "string", "source": "string", "category": "string", "imageUrl": "https://picsum.photos/200/200?random=1"}
      ] (exactly 5 articles),
      "breakdown": ["string"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    // Normalize properties
    if (content.news && content.news.length > 5) {
      content.news = content.news.slice(0, 5);
    }

    return content;
  } catch (error) {
    console.error("Error fetching Gemini content:", error);
    return getFallbackContent(phase);
  }
}

