const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [currentPhase, setCurrentPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(null);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);

  const calculatePhase = useCallback(() => {
    const hour = new Date().getHours();
    // Timing logic as per request:
    // 5am - 12pm: Good morning
    // 1pm (13) to 4pm (16): The day rolls on
    // 5pm (17) to 8pm (20): Good evening
    // 9pm (21) to 4am: Late night recap

    if (hour >= 5 && hour < 13) return TimePhase.MORNING;
    if (hour >= 13 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT;
  }, []);

  const fetchLocation = useCallback(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setCoords({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => {
          console.error("Geolocation error:", error);
        }
      );
    }
  }, []);

