    setIsGenerating(true);
    const phase = calculatePhase();
    setCurrentPhase(phase);
    const data = await getBriefingContent(phase, coords?.lat, coords?.lng);
    setContent(data);

    // Maintain shimmer effect for 3 seconds to show 'generative illusion'
    setTimeout(() => {
      setIsGenerating(false);
    }, 3000);
  }, [calculatePhase, coords]);

