            {/* Breakdown Section (Conditional) */}
            {showBreakdown && content.breakdown && content.breakdown.length > 0 && (
              <section className={isGenerating ? 'shimmer-active rounded-[28px]' : ''}>
                <div className="text-[12px] font-bold text-[#0f172a]/30 mb-4 ml-1">
                  Heres is the break down of your day
