import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const locationContext = (lat && lng) 
    ? `The user is located at coordinates: ${lat}, ${lng}.` 
    : "The user's location is unknown, assume a general major city center.";

  const prompt = `
    Generate a Samsung-style AI daily briefing for: ${phase}.
    ${locationContext}
    DO NOT include any user names.

    Return JSON structure:
    {
      "weather": {
        "current": "string (A short phrase describing the sky like 'Heavy rainfall', 'Cloudy morning', 'Sunny skies')",
        "temp": number,
        "high": number,
        "low": number,
        "location": "string",
        "condition": "string",
        "sunset": "string",
        "comparison": "string",
        "forecast": []
      },
      "energyScore": number,
      "energyStatus": "string",
      "news": [
        {"title": "string", "source": "string", "category": "string", "imageUrl": "https://picsum.photos/200/200?random=1"}
      ] (exactly 5 items),
      "breakdown": ["string"] (3-4 items for the day's schedule),
      "summaryText": "string (A paragraph summary of weather and day like: 'Generally clear. Highs 29 to 31C and lows 13 to 15C.')"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    // Normalize News Count
    if (content.news && content.news.length > 5) {
      content.news = content.news.slice(0, 5);
    }

    // Strictly follow requested text requirements
    if (phase === TimePhase.MORNING) {
      content.greeting = "Good morning";
      content.subtext = `Your day starts with ${content.weather.current}. Have a cheerful day.`;
    } else if (phase === TimePhase.DAY) {
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
    } else if (phase === TimePhase.EVENING) {
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
    } else if (phase === TimePhase.LATE_NIGHT) {
      content.greeting = "Late night recap";
      content.subtext = "Have a Good Night";
    }

    return content as BriefContent;
  } catch (error) {
    console.error("Error fetching Gemini content:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  const weatherPhrase = "cloudy morning";
  let greeting = "";
  let subtext = "";

  if (phase === TimePhase.MORNING) {
    greeting = "Good morning";
    subtext = `Your day starts with ${weatherPhrase}. Have a cheerful day.`;
  } else if (phase === TimePhase.DAY) {
    greeting = "The day rolls on";
    subtext = "Enjoy the rest of the day";
  } else if (phase === TimePhase.EVENING) {
    greeting = "Good evening";
    subtext = "Enjoy the rest of your day";
  } else {
    greeting = "Late night recap";
    subtext = "Have a Good Night";
  }

  return {
    greeting,
    subtext,
    summaryText: "Generally clear. Highs 21 to 23C. Pleasant conditions expected.",
    weather: {
      current: "Clear",
      temp: 22,
      high: 23,
      low: 15,
      location: "Your location",
      condition: "Sunny",
      sunset: "6:45 PM",
      comparison: "Temperature similar to yesterday",
      forecast: []
    },
    energyScore: 85,
    energyStatus: "Balanced",
    news: Array(5).fill(null).map((_, i) => ({
      title: "Staying up to date with Galaxy intelligence",
      source: "Global News",
      category: "Update",
      imageUrl: `https://picsum.photos/200/200?random=${i}`
    })),
    breakdown: ["Routine tasks", "Check updates"]
  };
}

