import React, { useState, useEffect, useCallback } from 'react';
import { TimePhase, BriefContent } from './types';
import { getBriefingContent } from './geminiService';
import { WeatherCard } from './components/WeatherCard';
import { FocusScoreCard } from './components/FocusScoreCard';
import { NewsCard } from './components/NewsCard';

const GalaxyAiLogo = () => (
  <svg width="40" height="40" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="opacity-80">
    <defs>
      <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#3ebbd2" />
        <stop offset="100%" stopColor="#2575fc" />
      </linearGradient>
      <linearGradient id="grad2" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#6ee7b7" />
        <stop offset="100%" stopColor="#3b82f6" />
      </linearGradient>
    </defs>
    <path d="M58 21C58 21 61 40 82 48C61 56 58 75 58 75C58 75 55 56 34 48C55 40 58 21 58 21Z" fill="url(#grad1)" />
    <path d="M31 36C31 36 33 50 48 56C33 62 31 76 31 76C31 76 29 62 14 56C29 50 31 36 31 36Z" fill="url(#grad2)" />
    <path d="M36 13C36 13 37 23 44 27C37 31 36 41 36 41C36 41 35 31 28 27C35 23 36 13 36 13Z" fill="url(#grad2)" />
    <path d="M75 68C75 68 76 75 81 78C76 81 75 88 75 88C75 88 74 81 69 78C74 75 75 68 75 68Z" fill="url(#grad1)" />
  </svg>
);

const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [currentPhase, setCurrentPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(null);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [isFinishing, setIsFinishing] = useState<boolean>(false);

  const calculatePhase = useCallback(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 13) return TimePhase.MORNING;
    if (hour >= 13 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT;
  }, []);

  const fetchLocation = useCallback(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setCoords({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => console.error("Geolocation error:", error)
      );
    }
  }, []);

  const initialize = useCallback(async () => {
    setIsGenerating(true);
    setIsFinishing(false);

    const phase = calculatePhase();
    setCurrentPhase(phase);

    const startTime = Date.now();
    const dataPromise = getBriefingContent(phase, coords?.lat, coords?.lng);
    const data = await dataPromise;

    setContent(data);

    // MANDATORY DURATION: 5 full shimmer passes (1.8s * 5 = 9000ms)
    const minGenerationTime = 9000; 
    const elapsed = Date.now() - startTime;
    const remaining = Math.max(0, minGenerationTime - elapsed);

    setTimeout(() => {
      setIsFinishing(true); 
      setTimeout(() => {
        setIsGenerating(false); 
      }, 1200); 
    }, remaining); 
  }, [calculatePhase, coords]);

  useEffect(() => {
    fetchLocation();
  }, [fetchLocation]);

  useEffect(() => {
    initialize();
  }, [initialize]);

  const showBreakdown = currentPhase !== TimePhase.MORNING;

  const getShimmerClass = (type: 'text' | 'subtext' | 'summary') => {
    if (!isGenerating) return `shimmer-text-base ${type}-shimmer-finished`;
    if (isFinishing) return `shimmer-text-base ${type}-shimmer-finished opacity-100`;
    return `shimmer-text-base ${type}-shimmer`;
  };

  const getCardClass = () => {
    if (!isGenerating) return "";
    return isFinishing ? "shimmer-active shimmer-finishing" : "shimmer-active";
  };

  return (
    <div className="relative h-screen w-screen overflow-hidden flex flex-col items-center bg-gradient-to-tr from-[#dff9f6] via-[#e8f4f8] to-[#d8ecf9]">

      <div className="relative z-10 w-full max-w-md h-full flex flex-col pt-12 pb-12 px-8 overflow-y-auto scrollbar-hide">

        <div className="mb-6">
          <GalaxyAiLogo />
        </div>

        <header className="mb-10">
          {!content ? (
            <div className="space-y-4 animate-pulse">
              <div className="h-10 w-48 bg-black/10 rounded-full" />
              <div className="h-6 w-64 bg-black/10 rounded-full" />
              <div className="h-4 w-full bg-black/10 rounded-full mt-6" />
            </div>
          ) : (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                {content.greeting}
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                {content.subtext}
              </p>
              <p className={`text-[13px] mt-6 leading-relaxed max-w-[85%] font-medium ${getShimmerClass('summary')}`}>
                {content.summaryText}
              </p>
            </div>
          )}
        </header>

        {content && (
          <div className="delayed-content flex flex-col gap-10">

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Weather Today
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <WeatherCard data={content.weather} />
              </div>
            </section>

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Energy Insights
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <FocusScoreCard score={content.energyScore} status={content.energyStatus} />
              </div>
            </section>

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Current Affairs
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <NewsCard news={content.news} />
              </div>
            </section>

            {showBreakdown && content.breakdown && content.breakdown.length > 0 && (
              <section>
                <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                  Daily Breakdown
                </div>
                <div className={`bg-white rounded-[28px] p-6 w-full shadow-sm border border-gray-100 ${getCardClass()}`}>
                  <div className="space-y-4">
                    {content.breakdown.map((item, i) => (
                      <div key={i} className="flex gap-4 items-center">
                        <div className="w-1.5 h-1.5 rounded-full bg-blue-400 shrink-0" />
                        <span className="text-[14px] font-medium text-[#0f172a]/80 leading-tight">
                          {item}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </section>
            )}

            <div className="pb-32" />
          </div>
        )}
      </div>

      <div className="absolute bottom-4 w-32 h-1 bg-black/10 rounded-full left-1/2 -translate-x-1/2 z-50" />
    </div>
  );
};

export default App;

