              </div>
            </section>

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Current Affairs
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
