import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const locationContext = (lat && lng) 
    ? `The user is at Latitude: ${lat}, Longitude: ${lng}. Use Google Search to find EXACT current weather and top local news for this precise location.` 
    : "The user's location is unknown, fetch general top global news and weather for a major hub.";

  const prompt = `
    Generate a Samsung-style AI daily briefing for the following phase: ${phase}.
    ${locationContext}

    Requirements:
    - Weather: Get real current temperature, high/low, and conditions for the provided location.
    - News: 5 real current headlines from today.
    - Summary: A concise paragraph reflecting the actual weather and news context.
    - DO NOT include user names.

    Return ONLY JSON:
    {
      "weather": {
        "current": "string (e.g., 'Cloudy afternoon')",
        "temp": number,
        "high": number,
        "low": number,
        "location": "string (City or neighborhood name)",
        "condition": "string (Sky state)",
        "sunset": "string (Time)",
        "comparison": "string (Relative to yesterday)",
        "forecast": []
      },
      "energyScore": number,
      "energyStatus": "string",
      "news": [
        {"title": "string", "source": "string", "category": "string", "imageUrl": "https://picsum.photos/200/200?random=1"}
      ],
      "breakdown": ["string"] (3-4 schedule items),
      "summaryText": "string"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    if (content.news && content.news.length > 5) {
      content.news = content.news.slice(0, 5);
    }

    // Force strict subtext requirements
    if (phase === TimePhase.MORNING) {
      content.greeting = "Good morning";
      content.subtext = `Your day starts with ${content.weather.current}. Have a cheerful day.`;
    } else if (phase === TimePhase.DAY) {
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
    } else if (phase === TimePhase.EVENING) {
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
    } else if (phase === TimePhase.LATE_NIGHT) {
      content.greeting = "Late night recap";
      content.subtext = "Have a Good Night.";
    }

    return content as BriefContent;
  } catch (error) {
    console.error("Error fetching briefing:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  const defaults = {
    greeting: phase === TimePhase.LATE_NIGHT ? "Late night recap" : "Good morning",
    subtext: phase === TimePhase.LATE_NIGHT ? "Have a Good Night." : "Have a cheerful day.",
    summaryText: "Generally clear. Pleasant conditions expected throughout the period.",
    weather: {
      current: "Clear", temp: 22, high: 24, low: 16,
      location: "Your Area", condition: "Sunny",
      sunset: "7:02 PM", comparison: "Similar to yesterday", forecast: []
    },
    energyScore: 88,
    energyStatus: "Balanced",
    news: Array(5).fill(null).map((_, i) => ({
      title: "Staying up to date with Galaxy intelligence",
      source: "Global News",
      category: "Update",
      imageUrl: `https://picsum.photos/200/200?random=${i}`
    })),
    breakdown: ["Routine updates", "Check notifications"]
  };
  return defaults as BriefContent;
}

