          {!content ? (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                Analyzing your day...
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                Galaxy AI is processing local insights
              </p>
            </div>
          ) : (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                {content.greeting}
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                {content.subtext}
              </p>
              <p className={`text-[13px] mt-6 leading-relaxed max-w-[85%] font-medium ${getShimmerClass('summary')}`}>
                {content.summaryText}
              </p>
            </div>
          )}
        </header>

        {content && (
          <div className="delayed-content flex flex-col gap-10">
            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Weather in {content.weather.location}
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <WeatherCard data={content.weather} />
              </div>
            </section>

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Energy Score
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <FocusScoreCard score={content.energyScore} status={content.energyStatus} />
              </div>
            </section>

            <section>
              <div className="text-[11px] font-bold text-[#0f172a]/30 mb-4 ml-1 uppercase tracking-widest">
                Recent News
              </div>
              <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                <NewsCard news={content.news} />
