import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  // Hardcoded target context: Howrah, West Bengal
  const locationContext = (lat && lng) 
    ? `The user is currently at Latitude: ${lat}, Longitude: ${lng} (Howrah, West Bengal region). Use Google Search to get the EXACT real-time weather and news for Howrah.`
    : `The user is in Howrah, West Bengal. Use Google Search to fetch current weather conditions, temperature, and local news for Howrah specifically.`;

  const prompt = `
    Generate a Samsung-style AI daily briefing for the phase: ${phase}.
    ${locationContext}

    Requirements:
    - Weather: Current temp, High/Low, and Condition (e.g. 'Hazy', 'Clear') for Howrah.
    - News: 5 real local headlines for West Bengal/Howrah from today.
    - Summary: A friendly summary paragraph.
    - DO NOT include user names.

    Return ONLY JSON:
    {
      "weather": {
        "current": "string (Sky state)",
        "temp": number,
        "high": number,
        "low": number,
        "location": "Howrah, West Bengal",
        "condition": "string",
        "sunset": "string",
        "comparison": "string",
        "forecast": []
      },
      "energyScore": number,
      "energyStatus": "string",
      "news": [
        {"title": "string", "source": "string", "category": "string", "imageUrl": "https://picsum.photos/200/200?random=1"}
      ],
      "breakdown": ["string"],
      "summaryText": "string"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    // Normalize counts
    if (content.news && content.news.length > 5) {
      content.news = content.news.slice(0, 5);
    }

    // Strictly enforce subtext requirements
    if (phase === TimePhase.MORNING) {
      content.greeting = "Good morning";
      content.subtext = `Your day in Howrah starts with ${content.weather.current}. Have a cheerful day.`;
    } else if (phase === TimePhase.DAY) {
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
    } else if (phase === TimePhase.EVENING) {
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
    } else if (phase === TimePhase.LATE_NIGHT) {
      content.greeting = "Late night recap";
      content.subtext = "Have a Good Night.";
    }

    return content as BriefContent;
  } catch (error) {
    console.error("Error fetching briefing content:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  const defaults = {
    greeting: phase === TimePhase.LATE_NIGHT ? "Late night recap" : "Good morning",
    subtext: phase === TimePhase.LATE_NIGHT ? "Have a Good Night." : "Have a cheerful day.",
    summaryText: "Generally clear in Howrah. Pleasant breezes from the river. Stay updated with your local news below.",
    weather: {
      current: "Clear Night", temp: 24, high: 31, low: 22,
      location: "Howrah, West Bengal", condition: "Clear",
      sunset: "6:15 PM", comparison: "Similar to yesterday", forecast: []
    },
    energyScore: 82,
    energyStatus: "Balanced",
    news: Array(5).fill(null).map((_, i) => ({
      title: "Latest news from West Bengal region",
      source: "WB Updates",
      category: "Local",
      imageUrl: `https://picsum.photos/200/200?random=${i}`
    })),
    breakdown: ["Daily routine", "Local check-in"]
  };
  return defaults as BriefContent;
}

