import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const locationContext = "The user is in Howrah, West Bengal. Use Google Search to find REAL-TIME weather (exact sky condition like 'Heavy rainfall', 'Mist', or 'Cloudy morning') and 5 local news headlines for Howrah today.";

  const prompt = `
    Generate a Samsung-style AI daily briefing for the phase: ${phase}.
    ${locationContext}

    Requirements:
    - Weather: Accurate for Howrah, West Bengal right now.
    - News: 5 real local headlines for Howrah/West Bengal.
    - Summary: A short summary of the outlook (no names).
    - Breakdown: Provide 3-4 bullet points for a daily schedule.
    - DO NOT include names in any part of the briefing.

    Return ONLY JSON:
    {
      "weather": {
        "current": "string (A descriptive condition like 'Heavy rainfall', 'Cloudy morning', or 'Clear night')",
        "temp": number,
        "high": number,
        "low": number,
        "location": "Howrah, West Bengal",
        "condition": "string",
        "sunset": "string",
        "comparison": "string",
        "forecast": []
      },
      "energyScore": number,
      "energyStatus": "string",
      "news": [
        {"title": "string", "source": "string", "category": "string", "imageUrl": "https://picsum.photos/200/200?random=1"}
      ],
      "breakdown": ["string"],
      "summaryText": "string"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      },
    });

    const content = JSON.parse(response.text || "{}");

    // Strictly enforce subtext requirements based on user prompt
    switch (phase) {
      case TimePhase.MORNING:
        content.greeting = "Good morning";
        content.subtext = `Your day starts with ${content.weather.current}. Have a cheerful day.`;
        break;
      case TimePhase.DAY:
        content.greeting = "The day rolls on";
        content.subtext = "Enjoy the rest of the day";
        break;
      case TimePhase.EVENING:
        content.greeting = "Good evening";
        content.subtext = "Enjoy the rest of your day";
        break;
      case TimePhase.LATE_NIGHT:
        content.greeting = "Late night recap";
        content.subtext = "Have a Good and Restful Night";
        break;
    }

    return content as BriefContent;
  } catch (error) {
    console.error("Error fetching briefing content:", error);
    return getFallbackContent(phase);
  }
}

function getFallbackContent(phase: TimePhase): BriefContent {
  const fallbackWeather = {
    current: phase === TimePhase.MORNING ? "Cloudy morning" : "Clear skies", 
    temp: 26, high: 31, low: 23,
    location: "Howrah, West Bengal", condition: "Clear",
    sunset: "6:18 PM", comparison: "Temperature same as yesterday", forecast: []
  };

  const content: any = {
    weather: fallbackWeather,
    energyScore: 88,
    energyStatus: "Excellent",
    news: Array(5).fill(null).map((_, i) => ({
      title: "Latest update from Howrah Municipal Corporation",
      source: "Howrah Daily",
      category: "Local",
      imageUrl: `https://picsum.photos/200/200?random=${i + 10}`
    })),
    breakdown: ["Review morning emails", "Lunch meeting at 1 PM", "Evening relaxation"],
    summaryText: "The weather in Howrah remains pleasant. A great day to stay focused and productive."
  };

  switch (phase) {
    case TimePhase.MORNING:
      content.greeting = "Good morning";
      content.subtext = `Your day starts with ${fallbackWeather.current}. Have a cheerful day.`;
      break;
    case TimePhase.DAY:
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
      break;
    case TimePhase.EVENING:
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
      break;
    case TimePhase.LATE_NIGHT:
      content.greeting = "Late night recap";
      content.subtext = "Have a Good and Restful Night";
      break;
  }

  return content as BriefContent;
}

