import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview";

  const locationPrompt = lat && lng ? `The user is at latitude ${lat}, longitude ${lng}.` : "The user is in an unknown location, assume a general context or Howrah as a fallback.";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a "Now brief" for a Samsung device.
    Generate a high-quality, concise, and helpful briefing based on the time of day.

    Current Phase: ${phase}
    ${locationPrompt}

    Rules for output:
    1. Greeting: A warm "Good morning", "Good afternoon", "Good evening", or "Late night recap".
    2. Subtext: 
       - If phase is LATE_NIGHT, MUST be exactly "Have a Good and Restful Night".
       - Otherwise, a short contextual sentence about the user's status or location.
    3. summaryText: A 2-3 sentence summary of the day's highlights.
    4. weather: Accurate-looking mock data for temperature and conditions.
    5. youtubeUploads: 2-3 interesting mock video titles with realistic metadata.
    6. news: 2-3 current affair headlines with sources and categories.
    7. breakdown: A list of 3-4 timeline points for the user's day.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: "Generate the briefing content now.",
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          greeting: { type: Type.STRING },
          subtext: { type: Type.STRING },
          summaryText: { type: Type.STRING },
          weather: {
            type: Type.OBJECT,
            properties: {
              current: { type: Type.STRING },
              temp: { type: Type.NUMBER },
              high: { type: Type.NUMBER },
              low: { type: Type.NUMBER },
              location: { type: Type.STRING },
              condition: { type: Type.STRING },
              sunset: { type: Type.STRING },
              comparison: { type: Type.STRING },
              forecast: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    time: { type: Type.STRING },
                    temp: { type: Type.NUMBER },
                    icon: { type: Type.STRING }
                  }
                }
              }
            }
          },
          youtubeUploads: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                channel: { type: Type.STRING },
                thumbnail: { type: Type.STRING },
                views: { type: Type.STRING },
                time: { type: Type.STRING }
              }
            }
          },
          news: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                source: { type: Type.STRING },
                category: { type: Type.STRING },
                imageUrl: { type: Type.STRING }
              }
            }
          },
          breakdown: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      }
    }
  });

  const content = JSON.parse(response.text) as BriefContent;

  // Hard enforcement of the subtext requirement
  if (phase === TimePhase.LATE_NIGHT) {
    content.subtext = "Have a Good and Restful Night";
  }

  // Fallback thumbnails if AI doesn't provide valid ones
  content.youtubeUploads = content.youtubeUploads.map((v, i) => ({
    ...v,
    thumbnail: v.thumbnail || `https://picsum.photos/seed/yt${i}/320/180`
  }));
  content.news = content.news.map((n, i) => ({
    ...n,
    imageUrl: n.imageUrl || `https://picsum.photos/seed/news${i}/400/300`
  }));

  return content;
}

