        <div className="flex justify-between items-start mb-6">
          <GalaxyAiLogo />
        </div>

        <header className="mb-10">
          {!content ? (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                Initializing...
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                Galaxy AI is syncing your day
              </p>
            </div>
          ) : (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                {content.greeting}
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                {content.subtext}
              </p>
              <p className={`text-[13px] mt-6 leading-relaxed max-w-[85%] font-medium ${getShimmerClass('summary')}`}>
                {content.summaryText}
              </p>
            </div>
          )}
        </header>

        {content && (
          <div className="delayed-content flex flex-col gap-10">

            {/* Card 1: Weather */}
            {activeVisibility.weather && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's the weather today
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <WeatherCard data={content.weather} />
                </div>
              </section>
            )}

            {/* Card 2: YouTube Recent Uploads */}
            {activeVisibility.youtube && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's some recent uploads for you
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <YoutubeCard uploads={content.youtubeUploads} />
                </div>
              </section>
            )}

            {/* Card 3: News */}
            {activeVisibility.news && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's today's current affairs
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <NewsCard news={content.news} />
                </div>
              </section>
            )}

            {/* Breakdown Section */}
            {activeVisibility.routine && (currentPhase !== TimePhase.MORNING) && content.breakdown.length > 0 && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here is the breakdown of your day
                </div>
                <div className={`bg-white/40 backdrop-blur-md rounded-[28px] p-6 border border-white/50 shadow-sm ${getCardClass()}`}>
                  <ul className="space-y-3">
                    {content.breakdown.map((item, i) => (
                      <li key={i} className="flex items-start gap-3">
                        <div className="w-1.5 h-1.5 rounded-full bg-blue-400 mt-2 shrink-0" />
                        <span className="text-[14px] text-[#0f172a]/80 font-medium">{item}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </section>
            )}

            <div className="pb-40" />
          </div>
        )}
      </div>

      {/* STICKY FOOTER BUTTONS - FIXED */}
      <div className={`fixed bottom-12 right-8 z-[80] flex items-center gap-3 transition-all duration-700 ease-out ${!isGenerating && content ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'} ${showInfo || isSettingsOpen ? 'opacity-0 pointer-events-none' : ''}`}>
        <button 
          onClick={() => setShowInfo(true)}
          className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform"
        >
          <AlertCircle className="w-7 h-7 text-black/70" strokeWidth={1.2} />
        </button>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform"
