    <path d="M31 36C31 36 33 50 48 56C33 62 31 76 31 76C31 76 29 62 14 56C29 50 31 36 31 36Z" fill="url(#grad2)" />
    <path d="M36 13C36 13 37 23 44 27C37 31 36 41 36 41C36 41 35 31 28 27C35 23 36 13 36 13Z" fill="url(#grad2)" />
    <path d="M75 68C75 68 76 75 81 78C76 81 75 88 75 88C75 88 74 81 69 78C74 75 75 68 75 68Z" fill="url(#grad1)" />
  </svg>
);

const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [currentPhase, setCurrentPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [isGenerating, setIsGenerating] = useState<boolean>(false);
  const [isFinishing, setIsFinishing] = useState<boolean>(false);
  const [showInfo, setShowInfo] = useState<boolean>(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState<boolean>(false);
  const [showRefreshPopup, setShowRefreshPopup] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [pendingVisibility, setPendingVisibility] = useState({
    weather: true,
    youtube: true,
    news: true,
    routine: true
  });

  const [activeVisibility, setActiveVisibility] = useState({
    weather: true,
    youtube: true,
    news: true,
    routine: true
  });

  const initialized = useRef(false);

  const calculatePhase = useCallback(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return TimePhase.MORNING;
    if (hour >= 12 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT;
  }, []);

  const runInitialization = useCallback(async (lat?: number, lng?: number) => {
    setIsGenerating(true);
    setIsFinishing(false);
    setShowRefreshPopup(false);
    setError(null);

    setActiveVisibility({...pendingVisibility});

    const phase = calculatePhase();
    setCurrentPhase(phase);

    const startTime = Date.now();
    try {
      const data = await getBriefingContent(phase, lat, lng);
      setContent(data);

      const minTime = 3000;
      const elapsed = Date.now() - startTime;
      const delay = Math.max(0, minTime - elapsed);

      setTimeout(() => {
        setIsFinishing(true);
        setTimeout(() => {
          setIsGenerating(false);
        }, 1200);
      }, delay);
    } catch (err: any) {
      console.error("Failed to fetch briefing:", err);
      setError(err.message?.includes("quota") ? "API Quota Exceeded. Please try again later." : "Connection error. Galaxy AI couldn't sync your day.");
      setIsGenerating(false);
      setIsFinishing(false);
    }
  }, [calculatePhase, pendingVisibility]);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => runInitialization(pos.coords.latitude, pos.coords.longitude),
        () => runInitialization(),
        { timeout: 5000 }
      );
    } else {
      runInitialization();
    }
  }, [runInitialization]);

  const toggleVisibility = (key: keyof typeof pendingVisibility) => {
    setPendingVisibility(prev => ({ ...prev, [key]: !prev[key] }));
    setShowRefreshPopup(true);
  };

  const getShimmerClass = (type: 'text' | 'subtext' | 'summary') => {
    if (error) return "";
    if (!isGenerating) return `shimmer-text-base ${type}-shimmer-finished`;
    if (isFinishing) return `shimmer-text-base ${type}-shimmer-finished opacity-100`;
    return `shimmer-text-base ${type}-shimmer`;
  };

  const getCardClass = () => {
    if (error) return "";
    if (!isGenerating) return "";
    return isFinishing ? "shimmer-active shimmer-finishing" : "shimmer-active";
  };

  return (
    <div className="relative h-screen w-screen overflow-hidden flex flex-col items-center bg-gradient-to-tr from-[#dff9f6] via-[#e8f4f8] to-[#d8ecf9]">
      <div className={`relative z-10 w-full max-w-md h-full flex flex-col pt-12 pb-12 px-8 overflow-y-auto scrollbar-hide transition-all duration-500 ${showInfo || isSettingsOpen ? 'blur-[8px] pointer-events-none' : ''}`}>

        <div className="flex justify-between items-start mb-6">
          <GalaxyAiLogo />
        </div>

        <header className="mb-10">
          {error ? (
            <div className="flex flex-col bg-red-50/50 backdrop-blur-md p-6 rounded-[28px] border border-red-100 shadow-sm animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="flex items-center gap-3 mb-2">
                <AlertTriangle className="w-6 h-6 text-red-500" />
                <h1 className="text-[20px] font-bold text-[#0f172a]">Sync Interrupted</h1>
              </div>
              <p className="text-[14px] text-gray-600 mb-6 leading-relaxed">
                {error}
              </p>
              <button 
                onClick={() => runInitialization()}
                className="w-full py-3 bg-white/80 rounded-2xl text-[14px] font-bold text-[#0f172a] shadow-sm border border-gray-100 active:scale-95 transition-transform"
              >
                Retry Sync
              </button>
            </div>
          ) : !content ? (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                Initializing...
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                Galaxy AI is syncing your day
              </p>
            </div>
          ) : (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>
                {content.greeting}
              </h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>
                {content.subtext}
              </p>
              <p className={`text-[13px] mt-6 leading-relaxed max-w-[85%] font-medium ${getShimmerClass('summary')}`}>
                {content.summaryText}
              </p>
            </div>
          )}
        </header>

        {content && !error && (
          <div className="delayed-content flex flex-col gap-10">
            {activeVisibility.weather && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's the weather today
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <WeatherCard data={content.weather} />
                </div>
              </section>
            )}

            {activeVisibility.youtube && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's some recent uploads for you
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <YoutubeCard uploads={content.youtubeUploads} />
                </div>
              </section>
            )}

            {activeVisibility.news && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here's today's current affairs
                </div>
                <div className={`rounded-[28px] overflow-hidden ${getCardClass()}`}>
                  <NewsCard news={content.news} />
                </div>
              </section>
            )}

            {activeVisibility.routine && (currentPhase !== TimePhase.MORNING) && content.breakdown.length > 0 && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">
                  Here is the breakdown of your day
                </div>
                <div className={`bg-white/40 backdrop-blur-md rounded-[28px] p-6 border border-white/50 shadow-sm ${getCardClass()}`}>
                  <ul className="space-y-3">
                    {content.breakdown.map((item, i) => (
                      <li key={i} className="flex items-start gap-3">
                        <div className="w-1.5 h-1.5 rounded-full bg-blue-400 mt-2 shrink-0" />
                        <span className="text-[14px] text-[#0f172a]/80 font-medium">{item}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </section>
            )}

            <div className="pb-40" />
          </div>
        )}
      </div>

      <div className={`fixed bottom-12 right-8 z-[80] flex items-center gap-3 transition-all duration-700 ease-out ${(!isGenerating && (content || error)) ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'} ${showInfo || isSettingsOpen ? 'opacity-0 pointer-events-none' : ''}`}>
        <button 
          onClick={() => setShowInfo(true)}
          className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform"
        >
          <AlertCircle className="w-7 h-7 text-black/70" strokeWidth={1.2} />
        </button>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform"
        >
          <Settings className="w-7 h-7 text-black/70" strokeWidth={1.2} />
        </button>
      </div>

      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 z-[120] transition-all duration-500 ease-out ${showRefreshPopup && !isSettingsOpen ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-95 pointer-events-none'}`}>
        <button 
          onClick={() => {
            if ("geolocation" in navigator) {
              navigator.geolocation.getCurrentPosition(
                (pos) => runInitialization(pos.coords.latitude, pos.coords.longitude),
                () => runInitialization()
              );
            } else {
              runInitialization();
            }
          }}
          className="flex items-center gap-3 bg-white/95 backdrop-blur-md px-6 py-3 rounded-full shadow-2xl border border-white/60 active:scale-95 transition-transform group"
        >
          <span className="text-[14px] font-bold text-[#0f172a]">Refresh brief</span>
          <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center shadow-md group-hover:rotate-180 transition-transform duration-500">
            <RotateCw className="w-4 h-4 text-white" />
          </div>
        </button>
      </div>

      <div className={`fixed inset-0 z-[150] bg-white transition-all duration-500 cubic-bezier(0.25, 1, 0.5, 1) transform ${isSettingsOpen ? 'translate-y-0' : 'translate-y-full'}`}>
        <div className="h-full flex flex-col">
          <div className="flex items-center gap-4 px-6 pt-14 pb-4">
            <button onClick={() => setIsSettingsOpen(false)} className="p-2 -ml-2 active:scale-90 transition-transform">
              <ChevronLeft className="w-7 h-7 text-[#0f172a]" />
            </button>
            <h2 className="text-[22px] font-bold text-[#0f172a]">Content to include</h2>
          </div>

          <div className="px-6 py-4 flex-1 overflow-y-auto">
            <p className="text-[14px] text-gray-500 leading-relaxed mb-10 px-1">
              Choose which types of content to show in your Now brief. Content from categories you select will appear when relevant content is available. For categories you don't select, content won't be shown at all.
            </p>

            <div className="bg-gray-100/60 rounded-[32px] overflow-hidden border border-gray-100 shadow-sm">
              <SettingItem 
                icon={<Sun className="w-5 h-5 text-blue-500" />} 
                title="Weather & climate" 
                bgColor="bg-blue-100" 
                active={pendingVisibility.weather} 
                onToggle={() => toggleVisibility('weather')} 
              />
              <SettingItem 
                icon={<Youtube className="w-5 h-5 text-red-500" />} 
                title="Recent uploads" 
                bgColor="bg-red-100" 
                active={pendingVisibility.youtube} 
                onToggle={() => toggleVisibility('youtube')} 
              />
              <SettingItem 
                icon={<Newspaper className="w-5 h-5 text-orange-500" />} 
                title="Local news" 
                bgColor="bg-orange-100" 
                active={pendingVisibility.news} 
