        onClick={() => setShowInfo(false)}
      />

      <div className={`fixed inset-x-0 bottom-0 z-[100] px-4 pb-8 transition-transform duration-500 ease-out transform ${showInfo ? 'translate-y-0' : 'translate-y-full'}`}>
