import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-pro-preview"; // Using Pro for better tool use and grounding

  const locationText = lat && lng ? `at latitude ${lat}, longitude ${lng}` : "in Howrah, West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a "Now brief" for a Samsung device.
    You MUST use Google Search to find REAL-TIME, ACCURATE information.

    Location: ${locationText}.
    Current Phase: ${phase}.

    Mandatory Content Rules:
    1. Weather: Fetch current real-time data from "The Weather Channel" or equivalent reliable source for the location. Include a 'sourceUrl' pointing to the weather page.
    2. News: Fetch 3 real, current news headlines from "Google Discover" style sources specifically about India and West Bengal. Include the actual article URL.
    3. YouTube: Fetch 2-3 real, currently trending or popular YouTube videos. Provide their real YouTube watch URLs and real thumbnails. No placeholders.
    4. Greeting: Warm and contextual.
    5. Subtext: 
       - If phase is LATE_NIGHT, MUST be exactly "Have a Good Night".
       - Otherwise, a short contextual sentence.
    6. Breakdown: 3-4 timeline points for the day.

    Response MUST be valid JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate the live briefing content based on real-time search data.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            greeting: { type: Type.STRING },
            subtext: { type: Type.STRING },
            summaryText: { type: Type.STRING },
            weather: {
              type: Type.OBJECT,
              properties: {
                current: { type: Type.STRING },
                temp: { type: Type.NUMBER },
                high: { type: Type.NUMBER },
                low: { type: Type.NUMBER },
                location: { type: Type.STRING },
                condition: { type: Type.STRING },
                sunset: { type: Type.STRING },
                comparison: { type: Type.STRING },
                sourceUrl: { type: Type.STRING, description: "Link to The Weather Channel page" },
                forecast: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      time: { type: Type.STRING },
                      temp: { type: Type.NUMBER },
                      icon: { type: Type.STRING }
                    }
                  }
                }
              }
            },
            youtubeUploads: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  channel: { type: Type.STRING },
                  thumbnail: { type: Type.STRING },
                  views: { type: Type.STRING },
                  time: { type: Type.STRING },
                  url: { type: Type.STRING, description: "Full YouTube video URL" }
                }
              }
            },
            news: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  source: { type: Type.STRING },
                  category: { type: Type.STRING },
                  imageUrl: { type: Type.STRING },
                  articleUrl: { type: Type.STRING, description: "URL to the news article" }
                }
              }
            },
            breakdown: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["greeting", "subtext", "summaryText", "weather", "youtubeUploads", "news", "breakdown"]
        }
      }
    });

    const content = JSON.parse(response.text) as BriefContent;

    // Safety check for subtext requirement
    if (phase === TimePhase.LATE_NIGHT) {
      content.subtext = "Have a Good Night";
    }

    return content;
  } catch (error) {
    console.error("Gemini Search Grounding Failed:", error);
    throw error;
  }
}

