              </p>
            </div>
            <button onClick={() => setShowInfo(false)} className="mt-14 w-full text-[18px] font-bold text-[#0f172a] active:opacity-60 transition-opacity">
              OK
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

