    5. Subtext: 
       - If Phase is LATE_NIGHT, MUST be "Have a Good Night".
       - Otherwise, a short contextual line.
    6. Breakdown: Empty array.

    Return valid JSON matching the provided schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate my briefing for West Bengal, India.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            greeting: { type: Type.STRING },
            subtext: { type: Type.STRING },
            summaryText: { type: Type.STRING },
            weather: {
              type: Type.OBJECT,
              properties: {
                current: { type: Type.STRING },
                temp: { type: Type.NUMBER },
                high: { type: Type.NUMBER },
                low: { type: Type.NUMBER },
                location: { type: Type.STRING },
                condition: { type: Type.STRING },
                sunset: { type: Type.STRING },
                comparison: { type: Type.STRING },
                sourceUrl: { type: Type.STRING },
                forecast: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      time: { type: Type.STRING },
                      temp: { type: Type.NUMBER },
                      icon: { type: Type.STRING }
                    }
                  }
                }
              }
            },
            youtubeUploads: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  channel: { type: Type.STRING },
                  thumbnail: { type: Type.STRING },
                  views: { type: Type.STRING },
                  time: { type: Type.STRING },
                  url: { type: Type.STRING }
                }
              }
            },
            news: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  source: { type: Type.STRING },
                  category: { type: Type.STRING },
                  imageUrl: { type: Type.STRING },
                  articleUrl: { type: Type.STRING }
                }
              }
            },
            breakdown: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const content = JSON.parse(response.text) as BriefContent;
    if (phase === TimePhase.LATE_NIGHT) content.subtext = "Have a Good Night";
    return content;
  } catch (error) {
    console.warn("API Error, falling back to cached local content:", error);
    return getMockBriefingContent(phase);
  }
}

