    ],
    breakdown: []
  };
};

/**
 * Robustly extracts JSON from a string that might contain markdown backticks or extra text.
 */
function extractJson(text: string): any {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      return JSON.parse(jsonMatch[0]);
    }
    return JSON.parse(text);
  } catch (e) {
    throw new Error("Failed to parse response as JSON");
  }
}

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview"; // Faster, better quota limits
  const locationText = lat && lng ? `at lat: ${lat}, lng: ${lng}` : "in Howrah, West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a "Now brief" for a Samsung device.
    You MUST use Google Search for REAL-TIME information.

    Location Context: ${locationText}.
    Time Phase: ${phase}.

    Mandatory Rules:
    1. Weather: Use Google Search to find current data from The Weather Channel for ${locationText}. 
       - MUST include 'sourceUrl' for the weather.com location page.
    2. News: Fetch 3 real, actual news headlines from Google Discover or reputable news outlets about India and West Bengal.
       - MUST include real article URLs and real thumbnail images. NO PLACEHOLDERS.
    3. YouTube: Fetch 2-3 real, currently trending videos from the first page of youtube.com.
       - MUST include the actual YouTube watch URL and real thumbnails.
    4. Subtext: 
       - If Phase is LATE_NIGHT, MUST be exactly "Have a Good Night".
       - Otherwise, a short contextual sentence.
    5. Breakdown: Keep this as an empty array [].
    6. Images: Only use real URLs from the search results or high-quality Unsplash URLs (e.g. https://images.unsplash.com/...) that match the topic. NO broken or fake image URLs.

    Response MUST be valid JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: `Generate a detailed real-time briefing for West Bengal, India. Current time phase is ${phase}.`,
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    if (!response.text) throw new Error("Empty response from AI");

    const content = extractJson(response.text) as BriefContent;

    // Safety enforcement for user's specific text request
    if (phase === TimePhase.LATE_NIGHT) {
      content.subtext = "Have a Good Night";
      content.greeting = "Late night recap";
    }

    return content;
  } catch (error) {
    console.error("Gemini Briefing Generation failed:", error);
    // Return high-quality local data so the app NEVER gets stuck
    return getMockBriefingContent(phase);
  }
}

