              <button 
                onClick={() => runInitialization()}
                className="w-full py-3 bg-blue-600 rounded-2xl text-[14px] font-bold text-white shadow-md active:scale-95 transition-transform"
              >
                Retry
              </button>
            </div>
          ) : !content ? (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>Initializing...</h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>Galaxy AI is fetching your briefing</p>
            </div>
          ) : (
            <div className="flex flex-col">
              <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>{content.greeting}</h1>
              <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>{content.subtext}</p>
              <p className={`text-[13px] mt-6 leading-relaxed max-w-[85%] font-medium ${getShimmerClass('summary')}`}>{content.summaryText}</p>
            </div>
          )}
        </header>

        {content && !error && (
          <div className="delayed-content flex flex-col gap-10">
            {activeVisibility.weather && (
              <section>
                <div className="text-[13px] font-semibold text-[#0f172a]/40 mb-3 ml-1 tracking-tight">Weather Channel Updates</div>
