function extractJson(text: string): any {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
    return JSON.parse(text);
  } catch (e) {
    throw new Error("Invalid JSON structure from AI");
  }
}

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview"; 
  const locationText = lat && lng ? `near ${lat}, ${lng}` : "in West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant. Generate a "Now brief" for a Samsung device.

    SEARCH REQUIREMENTS:
    1. Weather: Fetch real current data for ${locationText} from The Weather Channel.
    2. News: Fetch 3 real headlines about India and West Bengal from Google Discover sources.
    3. YouTube: Fetch 2-3 real trending videos from the first page of youtube.com.

    CONTENT RULES:
    - Greeting: "Good morning", "Good afternoon", "Good evening", or "Late night recap".
    - Subtext (Phase ${phase}):
      - If LATE_NIGHT: MUST be "Have a Good Night".
      - If MORNING: MUST be "Your day is looking bright in [Location]".
      - Otherwise: A short contextual status update.
    - Images: Use real URLs from search or high-quality Unsplash URLs.

    Response must be valid JSON only.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate my briefing now.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const content = extractJson(response.text || "");

    // Final enforcement of specific text requests
    if (phase === TimePhase.LATE_NIGHT) {
      content.subtext = "Have a Good Night";
      content.greeting = "Late night recap";
    }

    return content;
  } catch (error) {
    console.error("Briefing Error:", error);
    return getMockBriefingContent(phase);
  }
}

