import { GoogleGenAI, Type } from "@google/genai";
import { TimePhase, BriefContent } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMockBriefingContent = (phase: TimePhase): BriefContent => {
  const isMorning = phase === TimePhase.MORNING;
  const isDay = phase === TimePhase.DAY;
  const isEvening = phase === TimePhase.EVENING;
  const isLateNight = phase === TimePhase.LATE_NIGHT;

  let greeting = "Good morning";
  let subtext = "Your day starts with a clear sky. Have a cheerful day.";

  if (isDay) {
    greeting = "The day rolls on";
    subtext = "Enjoy the rest of the day";
  } else if (isEvening) {
    greeting = "Good evening";
    subtext = "Enjoy the rest of your day";
  } else if (isLateNight) {
    greeting = "Late night recap";
    subtext = "Have a good and restful night";
  }

  return {
    greeting,
    subtext,
    summaryText: "Galaxy AI has prepared your daily overview based on real-time data.",
    weatherConditionSnippet: "clear sky",
    weather: {
      current: "Clear Skies",
      temp: 27,
      high: 31,
      low: 24,
      location: "Howrah, WB",
      condition: "Clear",
      sunset: "6:20 PM",
      comparison: "Similar to yesterday",
      sourceUrl: "https://weather.com/en-IN/weather/today/l/Howrah+West+Bengal",
      forecast: [
        { time: "Now", temp: 27, icon: "sun" },
        { time: "4PM", temp: 30, icon: "sun" },
        { time: "7PM", temp: 26, icon: "moon" }
      ]
    },
    youtubeUploads: [
      { title: "Trending in West Bengal", channel: "YouTube", thumbnail: "https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=500", views: "1.2M", time: "2h ago", url: "https://www.youtube.com" },
      { title: "Local Market Updates", channel: "News Hub", thumbnail: "https://images.unsplash.com/photo-1558431382-27e303142255?w=500", views: "45K", time: "5h ago", url: "https://www.youtube.com" }
    ],
    news: [
      { title: "Current Infrastructure Highlights in India", source: "Discover", category: "National", imageUrl: "https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=500", articleUrl: "https://www.google.com/search?q=india+news" },
      { title: "West Bengal Cultural Festival Starts", source: "Discover", category: "Local", imageUrl: "https://images.unsplash.com/photo-1589330664654-94ca64440232?w=500", articleUrl: "https://www.google.com/search?q=west+bengal+news" }
    ],
    breakdown: ["Checked weather updates", "Reviewed trending news", "Synthesized daily focus"]
  };
};

function extractJson(text: string): any {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
    return JSON.parse(text);
  } catch (e) {
    throw new Error("Invalid JSON structure from AI");
  }
}

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview"; 
  const locationText = lat && lng ? `near ${lat}, ${lng}` : "Howrah, West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a "Now brief".

    PHASE CONTEXT: ${phase}
    LOCATION: ${locationText}

    CONTENT RULES:
    1. Case Rule: All strings (greetings, subtexts, snippets) MUST be in Sentence case: "First letter capital and the rest shall be small."

    2. Phase-Based Wording:
       - MORNING (5am-12pm): Greeting is "Good morning" or "Time to shine". Subtext: "Your day starts with [weatherConditionSnippet]. Have a cheerful day."
       - DAY (1pm-4pm): Greeting is "The day rolls on". Subtext: "Enjoy the rest of the day".
       - EVENING (5pm-8pm): Greeting is "Good evening". Subtext: "Enjoy the rest of your day".
       - LATE_NIGHT (9pm-4am): Greeting is "Late night recap" or "Good night". Subtext: "Have a good and restful night".

    3. Weather Snippet:
       - Create a short descriptive snippet for weatherConditionSnippet like "heavy rainfall", "cloudy morning", or "clear sunshine". (Keep it lowercase except if it starts the subtext).

    4. Data Retrieval:
       - Use Google Search for live information from The Weather Channel (Howrah/WB), Discover News (India/WB), and YouTube trending.

    5. Breakdown:
       - Create a list of 3 points for "Here is the break down of your day".

    IMPORTANT: DO NOT USE ANY NAMES.
    Response must be valid JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate the brief following all phrasing and case rules.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const content = extractJson(response.text || "");

    // Manual String Normalization to ensure "First letter capital, rest small"
    const toSentenceCase = (str: string) => {
      if (!str) return "";
      return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
    };

    if (phase === TimePhase.MORNING) {
      content.greeting = toSentenceCase(content.greeting || "Good morning");
      const snippet = content.weatherConditionSnippet ? content.weatherConditionSnippet.toLowerCase() : "a fresh start";
      content.subtext = `Your day starts with ${snippet}. Have a cheerful day.`;
    } else if (phase === TimePhase.DAY) {
      content.greeting = "The day rolls on";
      content.subtext = "Enjoy the rest of the day";
    } else if (phase === TimePhase.EVENING) {
      content.greeting = "Good evening";
      content.subtext = "Enjoy the rest of your day";
    } else if (phase === TimePhase.LATE_NIGHT) {
      content.greeting = toSentenceCase(content.greeting || "Late night recap");
      content.subtext = "Have a good and restful night";
    }

    return content;
  } catch (error) {
    console.error("Briefing Error:", error);
    return getMockBriefingContent(phase);
  }
}

