const NewsItem: React.FC<{ item: NewsArticle }> = ({ item }) => {
  const timerRef = useRef<number | null>(null);

  const startPress = () => {
    timerRef.current = window.setTimeout(() => {
      if (item.articleUrl) {
        window.open(item.articleUrl, '_blank');
      }
    }, 1500);
  };

  const endPress = () => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  };

  // Improved placeholder logic for missing images
  const imageUrl = item.imageUrl && item.imageUrl.startsWith('http') 
    ? item.imageUrl 
    : `https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=600&q=80`;

  return (
    <div 
      onMouseDown={startPress}
      onMouseUp={endPress}
      onMouseLeave={endPress}
      onTouchStart={startPress}
      onTouchEnd={endPress}
      className="flex gap-4 items-center py-1 cursor-pointer active:bg-gray-50 rounded-xl transition-all select-none group"
    >
      <div className="w-[100px] h-[75px] rounded-2xl overflow-hidden bg-gray-100 shrink-0 border border-gray-100 shadow-sm">
         <img 
          src={imageUrl} 
          alt="" 
          loading="lazy"
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
         />
      </div>
      <div className="flex-1 min-w-0">
        <h3 className="text-[14px] font-bold text-[#0f172a] leading-[1.3] line-clamp-2 tracking-tight">
          {item.title}
        </h3>
        <div className="flex items-center gap-2 mt-1.5">
          <span className="text-[11px] text-blue-600 font-bold tracking-tight">{item.source}</span>
          <div className="w-1 h-1 rounded-full bg-gray-200" />
          <span className="text-[11px] text-gray-400 font-medium">{item.category}</span>
