import React, { useRef } from 'react';
import { Sun, Cloud, CloudRain, Moon } from 'lucide-react';
import { WeatherData } from '../types';

const WeatherIcon = ({ condition, className = "" }: { condition?: string; className?: string }) => {
  const cond = (condition || 'clear').toLowerCase();
  if (cond.includes('sun') || cond.includes('clear')) return <Sun className={className} />;
  if (cond.includes('rain') || cond.includes('storm')) return <CloudRain className={className} />;
  if (cond.includes('moon') || cond.includes('night')) return <Moon className={className} />;
  return <Cloud className={className} />;
};

export const WeatherCard: React.FC<{ data: WeatherData }> = ({ data }) => {
  const timerRef = useRef<number | null>(null);

  const startPress = () => {
    timerRef.current = window.setTimeout(() => {
      const url = data?.sourceUrl || 'https://weather.com';
      window.open(url, '_blank');
    }, 1500);
  };

  const endPress = () => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  };

  if (!data) return null;

  return (
    <div 
      onMouseDown={startPress}
      onMouseUp={endPress}
      onMouseLeave={endPress}
      onTouchStart={startPress}
      onTouchEnd={endPress}
      className="bg-[#5c9ce6] rounded-[28px] p-6 w-full text-white shadow-lg overflow-hidden relative cursor-pointer active:scale-[0.98] transition-transform select-none"
    >
      <div className="flex justify-between items-start mb-6">
        <div className="flex items-center gap-3">
          <WeatherIcon condition={data.condition} className="w-8 h-8 text-yellow-300 fill-yellow-300" />
          <span className="text-[32px] font-medium leading-none">{data.temp || '--'}°</span>
          <div className="flex flex-col ml-1">
             <span className="text-[10px] opacity-80 font-bold">@{data.location || 'Unknown'}</span>
          </div>
        </div>
        <div className="text-right">
          <span className="text-[12px] opacity-90 block font-medium">{data.condition || 'Clear'}</span>
          <span className="text-[12px] opacity-70 block font-medium">H: {data.high || '--'}° L: {data.low || '--'}°</span>
        </div>
      </div>

      <div className="space-y-4 pt-4 border-t border-white/20">
        <div className="flex flex-col gap-1">
          <span className="text-[11px] opacity-60 uppercase tracking-wider font-bold">Update Summary</span>
          <span className="text-[13px] font-medium leading-tight">{data.comparison || 'Checking local trends...'}</span>
        </div>
        <div className="flex flex-col gap-1">
          <span className="text-[11px] opacity-60 uppercase tracking-wider font-bold">Celestial</span>
          <span className="text-[13px] font-medium">Sunset today at {data.sunset || '--:--'}</span>
        </div>
      </div>

      <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-white/10 to-transparent pointer-events-none" />
      <div className="absolute bottom-2 right-4 text-[8px] opacity-30 font-bold">Hold for details</div>
    </div>
  );
};

