        <div className={`fixed top-14 z-[250] bg-black/80 backdrop-blur-md px-6 py-3 rounded-full transition-all duration-500 transform ${showLabsToast ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0'}`}>
          <p className="text-white text-[14px] font-medium">Now Brief Labs has been enabled</p>
        </div>

        <div className={`fixed inset-0 z-[200] flex items-center justify-center px-8 transition-all duration-500 ${showEmptyStatePopup ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
           <div className={`bg-white/20 backdrop-blur-3xl p-10 rounded-[48px] border border-white/40 shadow-[0_20px_50px_rgba(0,0,0,0.1)] flex flex-col items-center text-center max-w-xs transition-transform duration-500 transform ${showEmptyStatePopup ? 'scale-100 translate-y-0' : 'scale-90 translate-y-10'}`}>
              <div className="w-16 h-16 rounded-full bg-blue-100/30 flex items-center justify-center mb-6 border border-white/20">
