                  <h1 className="text-[32px] font-black text-[#0f172a] tracking-tight mb-2 text-center">Now Brief</h1>
                  <p 
                    onMouseDown={startVersionPress}
                    onMouseUp={endVersionPress}
                    onMouseLeave={endVersionPress}
                    onTouchStart={startVersionPress}
