export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimePhase, BriefContent } from './types';
import { getBriefingContent, getMockBriefingContent, generateLabsSummary } from './geminiService';
import { WeatherCard } from './components/WeatherCard';
import { YoutubeCard } from './components/YoutubeCard';
import { NewsCard } from './components/NewsCard';
import { AlertCircle, Settings, ChevronLeft, Sun, Youtube, Newspaper, RotateCw, Lightbulb, ChevronRight, Info, FlaskConical, X, EyeOff } from 'lucide-react';

const STORAGE_KEY = 'now_brief_config_v11';
const LABS_UNLOCKED_KEY = 'now_brief_labs_unlocked';
const LABS_ENABLED_KEY = 'now_brief_labs_enabled';

type SettingsView = 'home' | 'customize' | 'about' | 'labs';
type MainView = 'brief' | 'summary';

const GalaxyAiLogo = () => (
  <svg width="40" height="40" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="opacity-80">
    <defs>
      <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#3ebbd2" />
        <stop offset="100%" stopColor="#2575fc" />
      </linearGradient>
      <linearGradient id="grad2" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#6ee7b7" />
        <stop offset="100%" stopColor="#3b82f6" />
      </linearGradient>
    </defs>
    <path d="M58 21C58 21 61 40 82 48C61 56 58 75 58 75C58 75 55 56 34 48C55 40 58 21 58 21Z" fill="url(#grad1)" />
    <path d="M31 36C31 36 33 50 48 56C33 62 31 76 31 76C31 76 29 62 14 56C29 50 31 36 31 36Z" fill="url(#grad2)" />
    <path d="M36 13C36 13 37 23 44 27C37 31 36 41 36 41C36 41 35 31 28 27C35 23 36 13 36 13Z" fill="url(#grad2)" />
    <path d="M75 68C75 68 76 75 81 78C76 81 75 88 75 88C75 88 74 81 69 78C74 75 75 68 75 68Z" fill="url(#grad1)" />
  </svg>
);

const LOADING_PHRASES = [
  "Creating text",
  "Generating you summery",
  "Crafting a quick read",
  "Transcribing texts into summary"
];

const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [currentPhase, setCurrentPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [isGenerating, setIsGenerating] = useState<boolean>(true);
  const [isFinishing, setIsFinishing] = useState<boolean>(false);
  const [showInfo, setShowInfo] = useState<boolean>(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState<boolean>(false);
  const [settingsView, setSettingsView] = useState<SettingsView>('home');
  const [mainView, setMainView] = useState<MainView>('brief');
  const [showRefreshPopup, setShowRefreshPopup] = useState<boolean>(false);
  const [showEmptyStatePopup, setShowEmptyStatePopup] = useState<boolean>(false);

  const [labsUnlocked, setLabsUnlocked] = useState(() => localStorage.getItem(LABS_UNLOCKED_KEY) === 'true');
  const [labsEnabled, setLabsEnabled] = useState(() => localStorage.getItem(LABS_ENABLED_KEY) === 'true');
  const [showLabsToast, setShowLabsToast] = useState(false);
  const [showDevCodePopup, setShowDevCodePopup] = useState(false);
  const [devCodeInput, setDevCodeInput] = useState('');

  const [summaryLoading, setSummaryLoading] = useState(false);
  const [summaryPhase, setSummaryPhase] = useState(0);
  const [generatedSummary, setGeneratedSummary] = useState('');
  const [summaryDataReady, setSummaryDataReady] = useState(false);

  const [pendingVisibility, setPendingVisibility] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { weather: true, youtube: true, news: true };
  });

  const [activeVisibility, setActiveVisibility] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { weather: true, youtube: true, news: true };
  });

  const initialized = useRef(false);
  const versionPressTimer = useRef<number | null>(null);

  const calculatePhase = useCallback(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return TimePhase.MORNING;
    if (hour >= 13 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT; 
  }, []);

  const runInitialization = useCallback(async (lat?: number, lng?: number) => {
    setIsGenerating(true);
    setIsFinishing(false);
    setShowRefreshPopup(false);
    setShowEmptyStatePopup(false);

    const startTime = Date.now();
    setActiveVisibility({...pendingVisibility});
    localStorage.setItem(STORAGE_KEY, JSON.stringify(pendingVisibility));

    const phase = calculatePhase();
    setCurrentPhase(phase);

    try {
      const data = await getBriefingContent(phase, lat, lng);
      setContent(data);
    } catch (err: any) {
      setContent(getMockBriefingContent(phase));
    } finally {
      const elapsed = Date.now() - startTime;
      const totalAnimationTime = 20500; 
      const remaining = Math.max(0, totalAnimationTime - elapsed);

      setTimeout(() => {
        setIsFinishing(true);
        setTimeout(() => {
          setIsGenerating(false);
          const isAnythingVisible = pendingVisibility.weather || pendingVisibility.youtube || pendingVisibility.news;
          if (!isAnythingVisible) {
            setTimeout(() => {
              setShowEmptyStatePopup(true);
            }, 1500);
          }
        }, 800);
      }, remaining);
    }
  }, [calculatePhase, pendingVisibility]);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => runInitialization(pos.coords.latitude, pos.coords.longitude),
        () => runInitialization(),
        { timeout: 3000 }
      );
    } else {
      runInitialization();
    }
  }, [runInitialization]);

  const toggleVisibility = (key: keyof typeof pendingVisibility) => {
    setPendingVisibility((prev: any) => ({ ...prev, [key]: !prev[key] }));
    setShowRefreshPopup(true);
  };

  const getShimmerClass = (type: 'text' | 'subtext') => {
    if (!isGenerating) return `shimmer-text-base ${type}-shimmer-finished`;
    if (isFinishing) return `shimmer-text-base ${type}-shimmer-finished opacity-100`;
    return `shimmer-text-base ${type === 'text' ? 'text-shimmer' : 'subtext-shimmer'}`;
  };

  const getCardClass = () => {
    if (!isGenerating) return "";
    return isFinishing ? "shimmer-active shimmer-finishing" : "shimmer-active";
  };

  const handleOpenSettings = () => {
    setSettingsView('home');
    setIsSettingsOpen(true);
  };

  const startVersionPress = () => {
    versionPressTimer.current = window.setTimeout(() => {
      if (!labsUnlocked) {
        setLabsUnlocked(true);
        localStorage.setItem(LABS_UNLOCKED_KEY, 'true');
        setShowLabsToast(true);
        setTimeout(() => setShowLabsToast(false), 3000);
      }
    }, 2500);
  };

  const endVersionPress = () => {
    if (versionPressTimer.current) {
      clearTimeout(versionPressTimer.current);
      versionPressTimer.current = null;
    }
  };

  const handleLabsToggle = () => {
    if (labsEnabled) {
      setLabsEnabled(false);
      localStorage.setItem(LABS_ENABLED_KEY, 'false');
    } else {
      setShowDevCodePopup(true);
    }
  };

  const handleHideLabs = () => {
    setLabsUnlocked(false);
    localStorage.setItem(LABS_UNLOCKED_KEY, 'false');
    setSettingsView('home');
  };

  const checkDevCode = () => {
    if (devCodeInput === '+×÷=/_') {
      setLabsEnabled(true);
      localStorage.setItem(LABS_ENABLED_KEY, 'true');
      setShowDevCodePopup(false);
      setDevCodeInput('');
    } else {
      setDevCodeInput('');
    }
  };

  const triggerGenerateSummary = async () => {
    if (!content) return;
    setSummaryLoading(true);
    setGeneratedSummary('');
    setSummaryDataReady(false);
    setSummaryPhase(0);

    try {
      const summary = await generateLabsSummary(content.weather, content.news);
      setGeneratedSummary(summary);
      setSummaryDataReady(true);
    } catch (err) {
      setGeneratedSummary("Something went wrong during generation.");
      setSummaryDataReady(true);
    }
  };

  useEffect(() => {
    let interval: number | null = null;
    if (summaryLoading) {
      interval = window.setInterval(() => {
        setSummaryPhase((prev) => {
          const isLastPhase = prev === LOADING_PHRASES.length - 1;
          if (isLastPhase) {
            if (summaryDataReady) {
              setSummaryLoading(false);
              return prev;
            }
            return 0; // Loop back
          }
          return prev + 1;
        });
      }, 2500);
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [summaryLoading, summaryDataReady]);

  // Main Page View
  if (mainView === 'brief') {
    return (
      <div className="relative h-screen w-screen overflow-hidden flex flex-col items-center bg-gradient-to-tr from-[#dff9f6] via-[#e8f4f8] to-[#d8ecf9]">
        <div className={`relative z-10 w-full max-w-md h-full flex flex-col pt-12 pb-12 px-8 overflow-y-auto scrollbar-hide transition-all duration-500 ${showInfo || isSettingsOpen || showEmptyStatePopup || showLabsToast ? 'blur-[8px] scale-[0.98] pointer-events-none' : ''}`}>

          <div className="flex justify-between items-start mb-6">
            <GalaxyAiLogo />
          </div>

          <header className="mb-10 min-h-[120px]">
            {!content ? (
              <div className="flex flex-col animate-in fade-in duration-500">
                <h1 className={`text-[32px] font-medium tracking-tight leading-tight ${getShimmerClass('text')}`}>Initializing...</h1>
                <p className={`text-[16px] font-normal mt-1 ${getShimmerClass('subtext')}`}>Galaxy AI is preparing your brief</p>
              </div>
            ) : (
              <div className="flex flex-col animate-in fade-in slide-in-from-bottom-2 duration-700">
                <h1 className={`text-[36px] font-bold tracking-tight leading-tight ${getShimmerClass('text')}`}>
                  {content.greeting}
                </h1>
                <p className={`text-[17px] font-medium mt-1 leading-snug ${getShimmerClass('subtext')}`}>
                  {content.subtext}
                </p>
              </div>
            )}
          </header>

          {content && (
            <div className={`delayed-content flex flex-col gap-10 opacity-100`}>
              {labsEnabled && (
                 <button 
                  onClick={() => setMainView('summary')}
                  className="w-full bg-white/40 backdrop-blur-xl rounded-[28px] p-6 border border-white/60 shadow-sm flex items-center justify-between active:scale-95 transition-transform"
                 >
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center">
                        <FlaskConical className="w-5 h-5 text-indigo-600" />
                      </div>
                      <span className="text-[17px] font-bold text-[#0f172a]">Generate summary</span>
                   </div>
                   <ChevronRight className="w-5 h-5 text-gray-400" />
                 </button>
              )}

              {activeVisibility.weather && content.weather && (
                <section>
                  <div className={`text-[13px] font-bold text-[#0f172a]/60 mb-3 ml-1 tracking-tight ${getShimmerClass('subtext')}`}>
                    Weather for {content.weather.location || 'your area'}
                  </div>
                  <div className={`rounded-[32px] overflow-hidden ${getCardClass()}`}>
                    <WeatherCard data={content.weather} />
                  </div>
                </section>
              )}

              {activeVisibility.youtube && Array.isArray(content.youtubeUploads) && content.youtubeUploads.length > 0 && (
                <section>
                  <div className={`text-[13px] font-bold text-[#0f172a]/60 mb-3 ml-1 tracking-tight ${getShimmerClass('subtext')}`}>
                    Popular videos today
                  </div>
                  <div className={`rounded-[32px] overflow-hidden ${getCardClass()}`}>
                    <YoutubeCard uploads={content.youtubeUploads} />
                  </div>
                </section>
              )}

              {activeVisibility.news && Array.isArray(content.news) && content.news.length > 0 && (
                <section>
                  <div className={`text-[13px] font-bold text-[#0f172a]/60 mb-3 ml-1 tracking-tight ${getShimmerClass('subtext')}`}>
                    Top news updates
                  </div>
                  <div className={`rounded-[32px] overflow-hidden ${getCardClass()}`}>
                    <NewsCard news={content.news} />
                  </div>
                </section>
              )}

              <div className="pb-40" />
            </div>
          )}
        </div>

        {/* Buttons and Overlays */}
        <div className={`fixed bottom-12 right-8 z-[80] flex items-center gap-3 transition-all duration-700 ease-out ${content ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'} ${showInfo || isSettingsOpen || showEmptyStatePopup ? 'opacity-0 pointer-events-none' : ''}`}>
          <button onClick={() => setShowInfo(true)} className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform">
            <AlertCircle className="w-7 h-7 text-black/70" strokeWidth={1.2} />
          </button>
          <button onClick={handleOpenSettings} className="w-12 h-12 rounded-full flex items-center justify-center bg-white/40 backdrop-blur-xl border border-white/60 shadow-lg active:scale-90 transition-transform">
            <Settings className="w-7 h-7 text-black/70" strokeWidth={1.2} />
          </button>
        </div>

        <div className={`fixed bottom-12 left-8 z-[80] transition-all duration-700 ease-out ${showRefreshPopup && !isSettingsOpen ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-95 pointer-events-none'}`}>
          <button 
            onClick={() => runInitialization()} 
            className="flex items-center gap-3 bg-white/20 backdrop-blur-2xl px-5 py-3 rounded-full shadow-[0_8px_32px_0_rgba(31,38,135,0.07)] border border-white/40 active:scale-95 transition-all group overflow-hidden"
          >
            <div className="w-6 h-6 rounded-full flex items-center justify-center transition-transform duration-700 group-hover:rotate-180">
              <RotateCw className="w-4 h-4 text-black/60" />
            </div>
            <span className="text-[13px] font-bold text-black/70 tracking-tight">Refresh</span>
            <div className="absolute inset-0 bg-gradient-to-tr from-white/10 to-transparent pointer-events-none" />
          </button>
        </div>

        {/* Labs Unlocked Toast */}
        <div className={`fixed top-14 z-[250] bg-black/80 backdrop-blur-md px-6 py-3 rounded-full transition-all duration-500 transform ${showLabsToast ? 'translate-y-0 opacity-100' : '-translate-y-20 opacity-0'}`}>
          <p className="text-white text-[14px] font-medium">Now Brief Labs has been enabled</p>
        </div>

        {/* Settings */}
        <div className={`fixed inset-0 z-[150] bg-[#f2f2f7] transition-all duration-500 transform ${isSettingsOpen ? 'translate-y-0' : 'translate-y-full'}`}>
          <div className="h-full flex flex-col">
            <div className="flex items-center gap-4 px-6 pt-14 pb-4">
              <button onClick={() => { if (settingsView === 'home') setIsSettingsOpen(false); else setSettingsView('home'); }} className="p-2 -ml-2 active:scale-90 transition-transform">
                <ChevronLeft className="w-7 h-7 text-[#0f172a]" />
              </button>
              <h2 className="text-[22px] font-bold text-[#0f172a]">
                {settingsView === 'home' && 'Settings'}
                {settingsView === 'customize' && 'Customize Now brief'}
                {settingsView === 'about' && 'About Now brief'}
                {settingsView === 'labs' && 'Now Brief Labs'}
              </h2>
            </div>
            <div className="px-6 py-4 flex-1 overflow-y-auto">
              {settingsView === 'home' && (
                <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="bg-white rounded-[32px] overflow-hidden shadow-sm border border-white">
                    <MenuButton icon={<Settings className="w-5 h-5 text-gray-600" />} title="Customize Now brief" onClick={() => setSettingsView('customize')} />
                    {labsUnlocked && <MenuButton icon={<FlaskConical className="w-5 h-5 text-indigo-600" />} title="Now Brief Labs" onClick={() => setSettingsView('labs')} />}
                    <MenuButton icon={<Info className="w-5 h-5 text-gray-600" />} title="About Now brief" onClick={() => setSettingsView('about')} isLast />
                  </div>
                </div>
              )}
              {settingsView === 'customize' && (
                <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                   <div className="bg-white rounded-[32px] overflow-hidden shadow-sm border border-white">
                    <SettingToggleItem icon={<Sun className="w-5 h-5 text-blue-500" />} title="Weather updates" bgColor="bg-blue-50" active={pendingVisibility.weather} onToggle={() => toggleVisibility('weather')} />
                    <SettingToggleItem icon={<Youtube className="w-5 h-5 text-red-500" />} title="Popular videos" bgColor="bg-red-50" active={pendingVisibility.youtube} onToggle={() => toggleVisibility('youtube')} />
                    <SettingToggleItem icon={<Newspaper className="w-5 h-5 text-orange-500" />} title="Interesting news" bgColor="bg-orange-50" active={pendingVisibility.news} onToggle={() => toggleVisibility('news')} isLast />
                  </div>
                </div>
              )}
              {settingsView === 'labs' && (
                <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                   <div className="bg-white rounded-[32px] overflow-hidden shadow-sm border border-white">
                    <SettingToggleItem icon={<Lightbulb className="w-5 h-5 text-indigo-500" />} title="Summarize Now Brief" badge="New" bgColor="bg-indigo-50" active={labsEnabled} onToggle={handleLabsToggle} />
                    <SettingToggleItem icon={<EyeOff className="w-5 h-5 text-gray-500" />} title="Hide Now Brief Labs" bgColor="bg-gray-100" active={false} onToggle={handleHideLabs} isLast />
                  </div>
                </div>
              )}
              {settingsView === 'about' && (
                <div className="h-full flex flex-col items-center justify-center pb-20 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="mb-8 p-6 bg-white rounded-[40px] shadow-sm">
                     <GalaxyAiLogo />
                  </div>
                  <h1 className="text-[32px] font-black text-[#0f172a] tracking-tight mb-2 text-center">Now Brief</h1>
                  <p onMouseDown={startVersionPress} onMouseUp={endVersionPress} onMouseLeave={endVersionPress} onTouchStart={startVersionPress} onTouchEnd={endVersionPress} className="text-[18px] font-bold text-[#0f172a]/60 mb-10 text-center select-none cursor-pointer active:scale-95 transition-transform">v1.0</p>
                  <div className="bg-white/80 backdrop-blur-md px-10 py-6 rounded-[32px] border border-white shadow-sm flex flex-col items-center"><p className="text-[16px] font-black text-[#0f172a] text-center leading-tight">The latest version is already installed</p></div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Dev Code Popup */}
        <div className={`fixed inset-0 z-[300] flex items-center justify-center px-6 transition-all duration-300 ${showDevCodePopup ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
           <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setShowDevCodePopup(false)} />
           <div className="relative bg-white rounded-[44px] p-8 w-full max-w-sm shadow-2xl flex flex-col items-center">
              <h3 className="text-[18px] font-bold text-[#0f172a] mb-6">Enter developer code</h3>
              <input type="text" value={devCodeInput} onChange={(e) => setDevCodeInput(e.target.value)} placeholder="Code" className="w-full bg-gray-100 rounded-[20px] px-6 py-4 text-[16px] font-medium text-[#0f172a] focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all mb-8" />
              <div className="flex w-full gap-4">
                 <button onClick={() => setShowDevCodePopup(false)} className="flex-1 py-4 text-[16px] font-bold text-gray-400">Cancel</button>
                 <button onClick={checkDevCode} className="flex-1 py-4 bg-indigo-600 rounded-[24px] text-[16px] font-bold text-white active:scale-95 transition-transform">Ok</button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  // Summary Page View
  return (
    <div className="h-screen w-screen bg-[#f2f2f7] flex flex-col items-center p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="w-full max-w-md flex flex-col h-full">
        <header className="flex items-center gap-4 py-8">
           <button onClick={() => setMainView('brief')} className="p-2 -ml-2 active:scale-90 transition-transform">
             <ChevronLeft className="w-7 h-7 text-[#0f172a]" />
           </button>
           <h2 className="text-[22px] font-bold text-[#0f172a]">Now Brief summery</h2>
        </header>

        <div className="flex-1 flex flex-col justify-center gap-10">
           <div className={`bg-white rounded-[48px] p-10 min-h-[350px] shadow-sm border border-white flex flex-col items-center justify-center transition-all duration-700 overflow-hidden relative ${generatedSummary && !summaryLoading ? 'shimmer-active' : ''}`}>
              {summaryLoading ? (
                 <div className="flex flex-col items-center justify-center w-full min-h-[100px] text-center">
                    <p key={summaryPhase} className="text-[20px] font-bold text-[#0f172a]/70 tracking-tight animate-in fade-in slide-in-from-bottom-2 duration-1000">
                      {LOADING_PHRASES[summaryPhase]}
                    </p>
                 </div>
              ) : generatedSummary ? (
                <div className="w-full h-full animate-in fade-in duration-700">
                  <div className="flex items-center gap-3 mb-6">
                    <GalaxyAiLogo />
                    <span className="text-[12px] font-black text-indigo-600 tracking-widest uppercase">Summary Result</span>
                  </div>
                  <p className="text-[20px] font-bold text-[#0f172a] leading-snug">
                    {generatedSummary}
                  </p>
                </div>
              ) : (
                <div className="flex flex-col items-center text-center opacity-40">
                   <FlaskConical className="w-16 h-16 text-gray-300 mb-4" />
                   <p className="text-[16px] font-bold text-gray-400">Ready to synthesize</p>
                </div>
              )}
           </div>
        </div>

        <div className="py-12">
           <button 
            disabled={summaryLoading}
            onClick={triggerGenerateSummary}
            className="w-full h-16 rounded-full bg-gradient-to-r from-[#eef2ff] via-[#f0f9ff] to-[#e6fffa] flex items-center justify-center shadow-[0_0_30px_rgba(165,180,252,0.4),0_0_30px_rgba(153,246,228,0.4)] border border-white/60 active:scale-95 transition-all disabled:opacity-50"
           >
             <span className="text-[22px] font-bold text-[#1e293b] tracking-tight">Generate</span>
           </button>
        </div>
      </div>
    </div>
  );
};

// Subcomponents
const MenuButton: React.FC<{ icon: React.ReactNode; title: string; onClick: () => void; isLast?: boolean }> = ({ icon, title, onClick, isLast }) => (
  <button onClick={onClick} className={`w-full flex items-center justify-between p-6 active:bg-gray-50 transition-colors ${!isLast ? 'border-b border-gray-100' : ''}`}>
    <div className="flex items-center gap-4">
      <div className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center">{icon}</div>
      <span className="text-[16px] font-semibold text-[#0f172a]">{title}</span>
    </div>
    <ChevronRight className="w-5 h-5 text-gray-400" />
  </button>
);

const SettingToggleItem: React.FC<{ icon: React.ReactNode; title: string; bgColor: string; active: boolean; onToggle: () => void; isLast?: boolean; badge?: string; }> = ({ icon, title, bgColor, active, onToggle, isLast, badge }) => (
  <div className={`flex items-center justify-between p-6 ${!isLast ? 'border-b border-gray-100' : ''}`}>
    <div className="flex items-center gap-4">
      <div className={`w-11 h-11 rounded-full ${bgColor} flex items-center justify-center`}>{icon}</div>
      <div className="flex flex-col">
        <div className="flex items-center gap-2">
          <span className="text-[16px] font-semibold text-[#0f172a]">{title}</span>
          {badge && <span className="bg-[#ff8c00] text-white text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter">{badge}</span>}
        </div>
      </div>
    </div>
    <button onClick={onToggle} className={`w-12 h-7 rounded-full transition-colors relative duration-300 ${active ? 'bg-indigo-600' : 'bg-gray-300'}`}>
      <div className={`absolute top-1 left-1 w-5 h-5 bg-white rounded-full transition-transform duration-300 shadow-sm transform ${active ? 'translate-x-5' : 'translate-x-0'}`} />
    </button>
  </div>
);

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { TimePhase, BriefContent } from './types';
import { getBriefingContent, getMockBriefingContent, generateLabsSummary } from './geminiService';
import { WeatherCard } from './components/WeatherCard';
import { YoutubeCard } from './components/YoutubeCard';
import { NewsCard } from './components/NewsCard';
import { AlertCircle, Settings, ChevronLeft, Sun, Youtube, Newspaper, RotateCw, Lightbulb, ChevronRight, Info, FlaskConical, X, EyeOff } from 'lucide-react';

const STORAGE_KEY = 'now_brief_config_v11';
const LABS_UNLOCKED_KEY = 'now_brief_labs_unlocked';
const LABS_ENABLED_KEY = 'now_brief_labs_enabled';

type SettingsView = 'home' | 'customize' | 'about' | 'labs';
type MainView = 'brief' | 'summary';

const GalaxyAiLogo = () => (
  <svg width="40" height="40" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="opacity-80">
    <defs>
      <linearGradient id="grad1" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#3ebbd2" />
        <stop offset="100%" stopColor="#2575fc" />
      </linearGradient>
      <linearGradient id="grad2" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#6ee7b7" />
        <stop offset="100%" stopColor="#3b82f6" />
      </linearGradient>
    </defs>
    <path d="M58 21C58 21 61 40 82 48C61 56 58 75 58 75C58 75 55 56 34 48C55 40 58 21 58 21Z" fill="url(#grad1)" />
    <path d="M31 36C31 36 33 50 48 56C33 62 31 76 31 76C31 76 29 62 14 56C29 50 31 36 31 36Z" fill="url(#grad2)" />
    <path d="M36 13C36 13 37 23 44 27C37 31 36 41 36 41C36 41 35 31 28 27C35 23 36 13 36 13Z" fill="url(#grad2)" />
    <path d="M75 68C75 68 76 75 81 78C76 81 75 88 75 88C75 88 74 81 69 78C74 75 75 68 75 68Z" fill="url(#grad1)" />
  </svg>
);

const LOADING_PHRASES = [
  "Creating text",
  "Generating you summery",
  "Crafting a quick read",
  "Transcribing texts into summary"
];

const App: React.FC = () => {
  const [content, setContent] = useState<BriefContent | null>(null);
  const [currentPhase, setCurrentPhase] = useState<TimePhase>(TimePhase.MORNING);
  const [isGenerating, setIsGenerating] = useState<boolean>(true);
  const [isFinishing, setIsFinishing] = useState<boolean>(false);
  const [showInfo, setShowInfo] = useState<boolean>(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState<boolean>(false);
  const [settingsView, setSettingsView] = useState<SettingsView>('home');
  const [mainView, setMainView] = useState<MainView>('brief');
  const [showRefreshPopup, setShowRefreshPopup] = useState<boolean>(false);
  const [showEmptyStatePopup, setShowEmptyStatePopup] = useState<boolean>(false);

  const [labsUnlocked, setLabsUnlocked] = useState(() => localStorage.getItem(LABS_UNLOCKED_KEY) === 'true');
  const [labsEnabled, setLabsEnabled] = useState(() => localStorage.getItem(LABS_ENABLED_KEY) === 'true');
  const [showLabsToast, setShowLabsToast] = useState(false);
  const [showDevCodePopup, setShowDevCodePopup] = useState(false);
  const [devCodeInput, setDevCodeInput] = useState('');

  const [summaryLoading, setSummaryLoading] = useState(false);
  const [summaryPhase, setSummaryPhase] = useState(0);
  const [generatedSummary, setGeneratedSummary] = useState('');
  const [summaryDataReady, setSummaryDataReady] = useState(false);

  const [pendingVisibility, setPendingVisibility] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { weather: true, youtube: true, news: true };
  });

  const [activeVisibility, setActiveVisibility] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { weather: true, youtube: true, news: true };
  });

  const initialized = useRef(false);
  const versionPressTimer = useRef<number | null>(null);

  const calculatePhase = useCallback(() => {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return TimePhase.MORNING;
    if (hour >= 13 && hour < 17) return TimePhase.DAY;
    if (hour >= 17 && hour < 21) return TimePhase.EVENING;
    return TimePhase.LATE_NIGHT; 
  }, []);

  const runInitialization = useCallback(async (lat?: number, lng?: number) => {
    setIsGenerating(true);
    setIsFinishing(false);
    setShowRefreshPopup(false);
    setShowEmptyStatePopup(false);

    const startTime = Date.now();
    setActiveVisibility({...pendingVisibility});
    localStorage.setItem(STORAGE_KEY, JSON.stringify(pendingVisibility));

    const phase = calculatePhase();
    setCurrentPhase(phase);

    try {
      const data = await getBriefingContent(phase, lat, lng);
      setContent(data);
    } catch (err: any) {
      setContent(getMockBriefingContent(phase));
    } finally {
      const elapsed = Date.now() - startTime;
      const totalAnimationTime = 20500; 
      const remaining = Math.max(0, totalAnimationTime - elapsed);

      setTimeout(() => {
        setIsFinishing(true);
        setTimeout(() => {
          setIsGenerating(false);
          const isAnythingVisible = pendingVisibility.weather || pendingVisibility.youtube || pendingVisibility.news;
          if (!isAnythingVisible) {
            setTimeout(() => {
              setShowEmptyStatePopup(true);
            }, 1500);
          }
        }, 800);
      }, remaining);
    }
  }, [calculatePhase, pendingVisibility]);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => runInitialization(pos.coords.latitude, pos.coords.longitude),
        () => runInitialization(),
        { timeout: 3000 }
      );
    } else {
      runInitialization();
    }
  }, [runInitialization]);

