const toSentenceCase = (str: string) => {
  if (!str || typeof str !== 'string') return "";
  const trimmed = str.trim();
  if (trimmed.length === 0) return "";
  return trimmed.charAt(0).toUpperCase() + trimmed.slice(1).toLowerCase();
};

/**
 * Utility to retry an async function with exponential backoff
 */
async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = error?.message?.includes('429') || error?.status === 'RESOURCE_EXHAUSTED';
    if (isQuotaError && retries > 0) {
      console.warn(`Quota exceeded, retrying in ${delay}ms... (${retries} retries left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const getMockBriefingContent = (phase: TimePhase): BriefContent => {
  const isDay = phase === TimePhase.DAY;
  const isEvening = phase === TimePhase.EVENING;
  const isLateNight = phase === TimePhase.LATE_NIGHT;

  let greeting = "Good morning";
  let subtext = "Your day starts with a clear sky. Have a cheerful day.";

  if (isDay) {
    greeting = "The day rolls on";
    subtext = "Enjoy the rest of the day";
  } else if (isEvening) {
    greeting = "Good evening";
    subtext = "Enjoy the rest of your day";
  } else if (isLateNight) {
    greeting = "Late night recap";
    subtext = "Have a Good ";
  }

  return {
    greeting: toSentenceCase(greeting),
    subtext: subtext,
    summaryText: "Galaxy AI has prepared your daily overview based on real-time data.",
    weatherConditionSnippet: "clear sky",
    weather: {
      current: "Clear Skies",
      temp: 27,
      high: 31,
      low: 24,
      location: "Howrah, WB",
      condition: "Clear",
      sunset: "6:20 PM",
      comparison: "Similar to yesterday",
      sourceUrl: "https://weather.com/en-IN/weather/today/l/Howrah+West+Bengal",
      forecast: [
        { time: "Now", temp: 27, icon: "sun" },
        { time: "4PM", temp: 30, icon: "sun" },
        { time: "7PM", temp: 26, icon: "moon" }
      ]
    },
    youtubeUploads: [
      { title: "Kolkata travel guide 2025", channel: "India Vlogs", thumbnail: "https://images.unsplash.com/photo-1558431382-27e303142255?w=600", views: "1.2M", time: "2h ago", url: "https://www.youtube.com" },
      { title: "Street food of Howrah", channel: "Foodie Hub", thumbnail: "https://images.unsplash.com/photo-1626074353765-517a681e40be?w=600", views: "45K", time: "5h ago", url: "https://www.youtube.com" }
    ],
    news: [
      { title: "West Bengal infrastructure growth", source: "Discover", category: "National", imageUrl: "https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=600", articleUrl: "https://www.google.com/search?q=india+news" },
      { title: "Kolkata cultural festival highlights", source: "Discover", category: "Local", imageUrl: "https://images.unsplash.com/photo-1589330664654-94ca64440232?w=600", articleUrl: "https://www.google.com/search?q=west+bengal+news" }
    ],
    breakdown: []
  };
};

function extractJson(text: string): any {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview"; 
  const locationText = lat && lng ? `near ${lat}, ${lng}` : "Howrah, West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a "Now brief".

    PHASE CONTEXT: ${phase}
    LOCATION: ${locationText}

    CONTENT RULES:
    1. Case Rule: All strings MUST be in Sentence case (unless otherwise specified): "First letter capital and the rest shall be small."

    2. Phase-Based Wording:
       - MORNING: Greeting "Good morning". Subtext "Your day starts with [snippet]. Have a cheerful day."
       - DAY: Greeting "The day rolls on". Subtext "Enjoy the rest of the day".
       - EVENING: Greeting "Good evening". Subtext "Enjoy the rest of your day".
       - LATE_NIGHT: Greeting "Late night recap". Subtext "Have a Good "

    IMPORTANT: DO NOT USE ANY NAMES. Response must be valid JSON matching the BriefContent interface.
  `;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate the brief following all phrasing and case rules. Include real news from West Bengal and India.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const rawContent = extractJson(response.text || "");
    const mock = getMockBriefingContent(phase);

    const content: BriefContent = {
      ...mock,
      ...rawContent,
      greeting: rawContent?.greeting ? toSentenceCase(rawContent.greeting) : mock.greeting,
      subtext: (phase === TimePhase.LATE_NIGHT) ? "Have a Good " : (rawContent?.subtext ? rawContent.subtext : mock.subtext),
      breakdown: [], 
      news: Array.isArray(rawContent?.news) ? rawContent.news : mock.news,
      youtubeUploads: Array.isArray(rawContent?.youtubeUploads) ? rawContent.youtubeUploads : mock.youtubeUploads,
      weather: { ...mock.weather, ...(rawContent?.weather || {}) }
    };

    return content;
  }).catch(error => {
    console.error("Briefing Error after retries:", error);
    return getMockBriefingContent(phase);
  });
}

export async function generateLabsSummary(currentBrief: BriefContent | null, lat?: number, lng?: number): Promise<string> {
  const model = "gemini-3-pro-preview"; 
  const locationText = lat && lng ? `near coordinates ${lat}, ${lng} (West Bengal, India)` : "in West Bengal, India";

  const briefContext = currentBrief ? `
    CONTEXT FROM THE CURRENT BRIEF:
    - Weather: ${currentBrief.weather.current}, ${currentBrief.weather.temp}°C
    - News Headlines: ${currentBrief.news.map(n => n.title).join("; ")}
    - Youtube Trends: ${currentBrief.youtubeUploads.map(y => y.title).join("; ")}
  ` : "No brief context available.";

  const prompt = `
    Galaxy AI Labs Summary Generation Task:
    1. Analyze the provided Brief Context:
       ${briefContext}
    2. Perform Google Search for real-time updates in ${locationText} specifically for local news and current vibe.
    3. Synthesize everything into a single, highly polished executive summary paragraph (approx 40-50 words).

    TONE: Helpful, sleek, professional, Samsung Galaxy AI style.
    STRUCTURE: Start with the atmospheric context (weather/vibe), then blend the most significant news from West Bengal and National headlines.

    Output ONLY the summary text. No conversational filler.
  `;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });
    return response.text || "Unable to synthesize current data at this moment.";
  }).catch(err => {
    console.error("Labs Summary Error after retries:", err);
    if (err?.message?.includes('429')) {
      return "Galaxy AI search grounding quota reached. Please check back later for a fresh summary.";
    }
    return "Something went wrong during generation. Using cached or local data.";
  });
}

