function extractJson(text: string): any {
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

export async function getBriefingContent(phase: TimePhase, lat?: number, lng?: number): Promise<BriefContent> {
  const model = "gemini-3-flash-preview"; 
  const locationText = lat && lng ? `near ${lat}, ${lng}` : "Howrah, West Bengal, India";

  const systemInstruction = `
    You are a Galaxy AI assistant generating a premium "Now brief".

    PHASE CONTEXT: ${phase}
    LOCATION: ${locationText}

    CRITICAL INSTRUCTION: 
    - You MUST search Google for real-time information.
    - For images and thumbnails: You MUST find DIRECT, HIGH-QUALITY, and PUBLICLY ACCESSIBLE URLs. Avoid landing pages; find the actual image file paths (e.g., ending in .jpg, .png) or high-quality CDN links.
    - If a specific image URL is unavailable, use a high-quality Unsplash source URL that matches the context (e.g., https://images.unsplash.com/photo-[id]?w=800&q=80).

    TASK:
    1. Search Google for real-time local weather in ${locationText}.
    2. Search for 2 random currently popular YouTube videos (trending in India). Provide real URLs and direct high-quality thumbnail URLs from i.ytimg.com.
    3. Search for 2 random real Spotify tracks or playlists that fit the current time of day (${phase}). Provide real open.spotify.com URLs and real cover art thumbnail URLs.
    4. Search for the latest 3 real news headlines from Google News for India/West Bengal. Provide real article URLs and high-resolution image URLs.

    CONTENT RULES:
    1. Case Rule: All strings in Sentence case.
    2. Phase-Based Wording:
       - MORNING: Greeting "Good morning". Subtext "Your day starts with [snippet]. Have a cheerful day."
       - DAY: Greeting "The day rolls on". Subtext "Enjoy the rest of the day".
       - EVENING: Greeting "Good evening". Subtext "Enjoy the rest of your day".
       - LATE_NIGHT: Greeting "Late night recap". Subtext "Have a Good "

    Output valid JSON matching this structure:
    {
      "greeting": "...",
      "subtext": "...",
      "weather": { "current": "...", "temp": 25, "location": "...", "condition": "...", "sunset": "...", "comparison": "...", "sourceUrl": "...", "high": 28, "low": 22 },
      "youtubeUploads": [ { "title": "...", "channel": "...", "thumbnail": "...", "views": "...", "time": "...", "url": "..." } ],
      "spotifyItems": [ { "title": "...", "artist": "...", "thumbnail": "...", "url": "..." } ],
      "news": [ { "title": "...", "source": "...", "category": "...", "imageUrl": "...", "articleUrl": "..." } ]
    }
  `;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model,
      contents: "Generate the full briefing with optimized real-time images, news, and videos.",
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const rawContent = extractJson(response.text || "");
    const mock = getMockBriefingContent(phase);

    return {
      ...mock,
      ...rawContent,
      greeting: rawContent?.greeting ? toSentenceCase(rawContent.greeting) : mock.greeting,
      subtext: (phase === TimePhase.LATE_NIGHT) ? "Have a Good " : (rawContent?.subtext ? rawContent.subtext : mock.subtext),
      news: Array.isArray(rawContent?.news) ? rawContent.news : [],
      youtubeUploads: Array.isArray(rawContent?.youtubeUploads) ? rawContent.youtubeUploads : [],
      spotifyItems: Array.isArray(rawContent?.spotifyItems) ? rawContent.spotifyItems : []
    };
  }).catch(error => {
    console.error("Briefing Error:", error);
    return getMockBriefingContent(phase);
  });
}

export async function generateLabsSummary(currentBrief: BriefContent | null, lat?: number, lng?: number): Promise<string> {
  const model = "gemini-3-pro-preview"; 
  const locationText = lat && lng ? `near ${lat}, ${lng}` : "in West Bengal, India";

  const briefContext = currentBrief ? `
    CONTEXT:
    - Weather: ${currentBrief.weather.current}, ${currentBrief.weather.temp}°C
    - News: ${currentBrief.news.map(n => n.title).join("; ")}
    - Music: ${currentBrief.spotifyItems.map(s => s.title).join("; ")}
  ` : "No context.";

  const prompt = `
    Galaxy AI Synthesis:
    Use the context: ${briefContext}
    Provide a professional, sleek, Samsung Galaxy AI summary (40 words).
    Start with weather/vibe, then highlights of news and music recommendations.
    Output ONLY the summary text.
  `;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    return response.text || "Summary unavailable.";
  }).catch(err => {
    return "Galaxy AI is currently busy. Please try again later.";
  });
}

